src/components/status/StatusPanel.tsx:3:import { useTaskStore, type ToolName, type TaskEntry } from '../../stores/taskStore';

import { useMemo, useEffect, useState, useCallback, useRef } from 'react';
import { toast } from 'sonner';
import { ChevronUp, ChevronDown, AlertTriangle, RefreshCw, ArrowRightLeft, Trash2 } from 'lucide-react';
import { C, STATUS, LOG_COLOR } from '@/lib/theme';
import { AGENTS } from '@/lib/agents';
import { ScrollArea } from '@/components/ui/scroll-area';
import { useConfirmDialog } from '@/components/shared/ConfirmDialog';
import { useTaskStore, type TaskEntry, type ToolName } from '@/stores/taskStore';
import { useUIStore } from '@/stores/uiStore';
import { useTaskDispatch } from '@/hooks/useTaskDispatch';
import { removeTaskWithUndo } from '@/lib/undoableActions';
import { EmptyState } from '@/components/shared/EmptyState';
import { DecompositionErrorCard } from '@/components/orchestration/DecompositionErrorCard';

/* ── Types ─────────────────────────────────────────────── */

interface KanbanViewProps {
  selectedTask: string | null;
  setSelectedTask: (id: string) => void;
}

type ColumnKey = 'queued' | 'running' | 'done';

interface ColumnDef {
  key: ColumnKey;
  label: string;
  statusKey: keyof typeof STATUS;
}

interface MappedTask {
  id: string;
  title: string;
  prompt: string;
  agent: ToolName;
  column: ColumnKey;
  startedAt: number | null;
  duration: string | null;
  elapsedMs: number;
  status: TaskEntry['status'];
  role?: 'master' | 'worker';
  resultSummary?: string;
  lastOutputLine?: string;
}

/* ── Constants ─────────────────────────────────────────── */

const COLUMNS: ColumnDef[] = [
  { key: 'queued', label: 'Queued', statusKey: 'queued' },
  { key: 'running', label: 'In Progress', statusKey: 'running' },
  { key: 'done', label: 'Done', statusKey: 'done' },
];

/* ── Helpers ───────────────────────────────────────────── */

function mapColumn(status: TaskEntry['status']): ColumnKey {
  switch (status) {
    case 'pending':
    case 'routing':
    case 'waiting':
    case 'blocked':
      return 'queued';
    case 'running':
    case 'retrying':
    case 'falling_back':
    case 'failed':           // Failed stays in In Progress — user can retry
      return 'running';
    case 'completed':
    case 'review':
      return 'done';
    default:
      return 'queued';
  }
}

function formatDuration(ms: number): string {
  const s = Math.floor(ms / 1000);
  if (s < 60) return `${s}s`;
  const m = Math.floor(s / 60);
  return `${m}m ${s % 60}s`;
}

function formatElapsedTimer(ms: number): string {
  const totalSeconds = Math.floor(ms / 1000);
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  return `${minutes}:${seconds.toString().padStart(2, '0')}`;
}

/* ── Sub-components ────────────────────────────────────── */

function StatusDot({ color, size = 8 }: { color: string; size?: number }) {
  return (
    <span
      className="inline-block rounded-full shrink-0"
      style={{ width: size, height: size, background: color }}
    />
  );
}

function Pill({ children, bg, color }: { children: React.ReactNode; bg: string; color: string }) {
  return (
    <span
      className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[11px] font-semibold font-[Inter,sans-serif] leading-[18px]"
      style={{ background: bg, color }}
    >
      {children}
    </span>
  );
}

function PulsingDot({ color }: { color: string }) {
  return (
    <span
      className="animate-pulse inline-block w-2 h-2 rounded-full shrink-0"
      style={{ background: color }}
    />
  );
}

function RoleBadge({ role }: { role: 'master' | 'worker' }) {
  const isMaster = role === 'master';
  return (
    <span
      className={`inline-flex items-center gap-[3px] px-1.5 py-px rounded-md text-[9px] font-bold uppercase tracking-[0.04em] shrink-0 ${
        isMaster ? 'bg-amber-500/15 text-amber-500' : 'bg-violet-500/[0.12] text-violet-500'
      }`}
    >
      {isMaster ? '\u2605' : '\u25CB'} {role}
    </span>
  );
}

/** Indeterminate shimmer progress bar */
function IndeterminateProgress() {
  return (
    <div
      className="w-full h-1 rounded-sm overflow-hidden relative"
      style={{ background: C.border }}
    >
      <div
        className="shimmer-bar w-2/5 h-full rounded-sm absolute top-0 left-0"
        style={{ background: `linear-gradient(90deg, transparent, ${C.amber}, transparent)` }}
      />
    </div>
  );
}

/** Elapsed timer that updates every second */
function ElapsedTimer({ startedAt }: { startedAt: number }) {
  const [elapsed, setElapsed] = useState(() => Date.now() - startedAt);
  useEffect(() => {
    const interval = setInterval(() => setElapsed(Date.now() - startedAt), 1000);
    return () => clearInterval(interval);
  }, [startedAt]);

  return (
    <span className="text-[11px] font-[family-name:var(--font-mono)]" style={{ color: C.textMuted }}>
      {formatElapsedTimer(elapsed)}
    </span>
  );
}

/** Inline agent switcher dropdown for failed card */
function AgentSwitcher({
  currentAgent,
  onSwitch,
}: {
  currentAgent: ToolName;
  onSwitch: (agent: ToolName) => void;
}) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!open) return;
    function handleClick(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, [open]);

  const otherAgents = (Object.keys(AGENTS) as ToolName[]).filter((a) => a !== currentAgent);

  return (
    <div ref={ref} className="relative flex-1">
      <button
        type="button"
        onClick={(e) => { e.stopPropagation(); setOpen(!open); }}
        className="w-full py-1.5 px-2.5 rounded-lg bg-indigo-500/[0.08] border border-indigo-500/20 text-[11px] font-semibold font-[Inter,sans-serif] cursor-pointer flex items-center justify-center gap-[5px] transition-all duration-150 ease-in-out"
        style={{ color: C.accentText }}
        onMouseEnter={(e) => { e.currentTarget.style.background = 'rgba(99,102,241,0.15)'; }}
        onMouseLeave={(e) => { e.currentTarget.style.background = 'rgba(99,102,241,0.08)'; }}
      >
        <ArrowRightLeft size={11} />
        Switch
      </button>

      {open && (
        <div
          className="absolute bottom-[calc(100%+4px)] left-0 right-0 rounded-[10px] overflow-hidden z-20 shadow-[0_8px_24px_rgba(0,0,0,0.5)]"
          style={{ background: C.panel, border: `1px solid ${C.borderStrong}` }}
        >
          {otherAgents.map((agent) => {
            const info = AGENTS[agent];
            return (
              <button
                key={agent}
                type="button"
                onClick={(e) => {
                  e.stopPropagation();
                  setOpen(false);
                  onSwitch(agent);
                }}
                className="w-full flex items-center gap-2 py-2 px-2.5 bg-transparent border-none text-[11px] font-medium font-[Inter,sans-serif] cursor-pointer transition-[background] duration-150 ease-in-out"
                style={{ borderBottom: `1px solid ${C.border}`, color: C.textPrimary }}
                onMouseEnter={(e) => { e.currentTarget.style.background = C.surfaceHover; }}
                onMouseLeave={(e) => { e.currentTarget.style.background = 'transparent'; }}
              >
                <div
                  className="w-[18px] h-[18px] rounded-[5px] flex items-center justify-center text-[9px] font-bold text-white shrink-0"
                  style={{ background: info.gradient }}
                >
                  {info.letter}
                </div>
                {info.label}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

function TaskCard({
  task,
  selected,
  onClick,
  onRetry,
  onSwitchAgent,
  onDragStart,
  onDelete,
}: {
  task: MappedTask;
  selected: boolean;
  onClick: () => void;
  onRetry?: (task: MappedTask) => void;
  onSwitchAgent?: (task: MappedTask, newAgent: ToolName) => void;
  onDragStart?: (e: React.DragEvent, task: MappedTask) => void;
  onDelete?: (task: MappedTask) => void;
}) {
  const agent = AGENTS[task.agent];
  const isFailed = task.status === 'failed';
  const isRunning = task.column === 'running' && !isFailed;
  const isDone = task.column === 'done';
  const truncatedResult = task.resultSummary
    ? task.resultSummary.length > 120 ? task.resultSummary.slice(0, 117) + '...' : task.resultSummary
    : null;

  return (
    <button
      type="button"
      onClick={onClick}
      draggable={!!onDragStart}
      onDragStart={(e) => onDragStart?.(e, task)}
      className={`kanban-card-slide${isFailed ? ' failed-card-shake' : ''} w-full text-left p-3.5 rounded-2xl cursor-pointer transition-all duration-150 ease-in-out flex flex-col gap-2.5 font-[Inter,sans-serif]`}
      style={{
        background: isFailed ? C.redBg : C.surface,
        border: `1.5px solid ${selected ? C.accent : isFailed ? '#ef4444' + '60' : isRunning ? C.amber + '60' : C.border}`,
        opacity: task.status === 'blocked' ? 0.6 : 1,
      }}
    >
      {/* Title row with status indicator */}
      <div className="flex items-center gap-2">
        {isRunning && <PulsingDot color={C.amber} />}
        {isDone && (
          <span className="text-xs shrink-0">{'\u2713'}</span>
        )}
        {isFailed && (
          <AlertTriangle size={14} color="#ef4444" className="shrink-0" />
        )}
        <span
          className="text-[13px] font-semibold leading-5 overflow-hidden text-ellipsis whitespace-nowrap flex-1"
          style={{ color: C.textPrimary }}
        >
          {task.title}
        </span>
      </div>

      {/* Agent row with role badge */}
      <div className="flex items-center gap-2">
        <div
          className="w-5 h-5 rounded-md flex items-center justify-center text-[10px] font-bold text-white shrink-0"
          style={{ background: agent.gradient }}
        >
          {agent.letter}
        </div>
        <span className="text-xs" style={{ color: C.textSecondary }}>{AGENTS[task.agent].label}</span>
        {task.role && <RoleBadge role={task.role} />}
      </div>

      {/* Status badges for special states */}
      {task.status === 'blocked' && (
        <Pill bg="rgba(239,68,68,0.15)" color="#ef4444">
          <span style={{ fontSize: 10 }}>&#x1F512;</span> Blocked
        </Pill>
      )}
      {task.status === 'retrying' && (
        <Pill bg="rgba(245,158,11,0.15)" color="#f59e0b">
          <span style={{ fontSize: 10 }}>{'\u21BB'}</span> Retrying
        </Pill>
      )}
      {task.status === 'falling_back' && (
        <Pill bg="rgba(168,85,247,0.15)" color="#a855f7">
          <span style={{ fontSize: 10 }}>{'\u21C4'}</span> Reassigning
        </Pill>
      )}

      {/* Failed state — error message + elapsed time + inline actions */}
      {isFailed && (
        <>
          {/* Error preview */}
          {task.resultSummary && (
            <div
              style={{
                fontSize: 11,
                lineHeight: '16px',
                color: '#fca5a5',
                padding: '7px 10px',
                borderRadius: 8,
                background: 'rgba(248,113,113,0.06)',
                border: '1px solid rgba(248,113,113,0.12)',
                wordBreak: 'break-word',
                maxHeight: 48,
                overflow: 'hidden',
              }}
            >
              {task.resultSummary.length > 80 ? task.resultSummary.slice(0, 77) + '...' : task.resultSummary}
            </div>
          )}

          {/* Failure time */}
          {task.startedAt && task.elapsedMs > 0 && (
            <span style={{ fontSize: 11, color: C.textMuted }}>
              Failed after {formatDuration(task.elapsedMs)}
            </span>
          )}

          {/* Inline action buttons */}
          <div className="flex gap-1.5">
            {onRetry && (
              <button
                type="button"
                onClick={(e) => { e.stopPropagation(); onRetry(task); }}
                className="flex-1 py-1.5 px-2.5 rounded-lg bg-red-500/[0.12] border border-red-500/30 text-red-400 text-[11px] font-semibold font-[Inter,sans-serif] cursor-pointer flex items-center justify-center gap-[5px] transition-all duration-150 ease-in-out"
                onMouseEnter={(e) => {
                  e.currentTarget.style.background = 'rgba(239,68,68,0.2)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.background = 'rgba(239,68,68,0.12)';
                }}
              >
                <RefreshCw size={11} />
                Retry
              </button>
            )}

            {onSwitchAgent && (
              <AgentSwitcher
                currentAgent={task.agent}
                onSwitch={(newAgent) => onSwitchAgent(task, newAgent)}
              />
            )}

            {onDelete && (
              <button
                type="button"
                onClick={(e) => { e.stopPropagation(); onDelete(task); }}
                className="py-1.5 px-2.5 rounded-lg bg-red-500/[0.08] border border-red-500/20 text-red-400 text-[11px] font-semibold font-[Inter,sans-serif] cursor-pointer flex items-center justify-center gap-1 transition-all duration-150 ease-in-out"
                onMouseEnter={(e) => {
                  e.currentTarget.style.background = 'rgba(239,68,68,0.18)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.background = 'rgba(239,68,68,0.08)';
                }}
              >
                <Trash2 size={11} />
              </button>
            )}
          </div>
        </>
      )}

      {/* Indeterminate progress bar + elapsed timer (running) */}
      {isRunning && (
        <div className="flex flex-col gap-1.5">
          <IndeterminateProgress />
          {task.startedAt && (
            <div className="flex items-center justify-between">
              <span className="text-[10px]" style={{ color: C.textMuted }}>Running</span>
              <ElapsedTimer startedAt={task.startedAt} />
            </div>
          )}
        </div>
      )}

      {/* Live output preview (running tasks only) */}
      {isRunning && task.lastOutputLine && (
        <div
          className="text-[10px] leading-[15px] font-[family-name:var(--font-mono)] py-1.5 px-2 rounded-lg overflow-hidden text-ellipsis whitespace-nowrap max-h-8 opacity-80"
          style={{ color: C.textMuted, background: C.bg, border: `1px solid ${C.border}` }}
        >
          {task.lastOutputLine}
        </div>
      )}

      {/* Result summary (done cards) */}
      {isDone && truncatedResult && (
        <div
          className="text-[11px] leading-4 py-2 px-2.5 rounded-[10px] whitespace-pre-wrap break-words max-h-16 overflow-hidden"
          style={{
            color: C.textSecondary,
            background: C.panel,
            border: `1px solid ${C.border}`,
          }}
        >
          {truncatedResult}
        </div>
      )}

      {/* Duration (done) */}
      {task.duration && (
        <span className="text-[11px]" style={{ color: C.textMuted }}>{task.duration}</span>
      )}
    </button>
  );
}

/* ── Animation styles are defined in index.css ─────────── */

/* ── Main Component ────────────────────────────────────── */

export function KanbanView({ selectedTask, setSelectedTask }: KanbanViewProps) {
  const tasks = useTaskStore((s) => s.tasks);
  const orchestrationPhase = useTaskStore((s) => s.orchestrationPhase);
  const orchestrationLogs = useTaskStore((s) => s.orchestrationLogs);
  const projectDir = useUIStore((s) => s.projectDir);
  const { dispatchTask } = useTaskDispatch();
  const { confirm, ConfirmDialogElement } = useConfirmDialog();

  // Search & filter state
  const [searchQuery, setSearchQuery] = useState('');
  const [filterAgent, setFilterAgent] = useState<ToolName | 'all'>('all');
  const [filterStatus, setFilterStatus] = useState<ColumnKey | 'all'>('all');

  // Drag & drop state
  const [dragTaskId, setDragTaskId] = useState<string | null>(null);
  const [dropTarget, setDropTarget] = useState<ColumnKey | null>(null);

  // Activity log panel state
  const [logPanelOpen, setLogPanelOpen] = useState(false);
  const [logPanelHeight, setLogPanelHeight] = useState(200);
  const logScrollRef = useRef<HTMLDivElement>(null);
  const resizeRef = useRef<{ startY: number; startHeight: number } | null>(null);

  // Auto-scroll log panel to bottom on new entries
  useEffect(() => {
    if (logPanelOpen && logScrollRef.current) {
      logScrollRef.current.scrollTop = logScrollRef.current.scrollHeight;
    }
  }, [orchestrationLogs.length, logPanelOpen]);

  // Resize handler for log panel
  const handleResizeMouseDown = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    resizeRef.current = { startY: e.clientY, startHeight: logPanelHeight };
    const handleMouseMove = (me: MouseEvent) => {
      if (!resizeRef.current) return;
      const delta = resizeRef.current.startY - me.clientY;
      setLogPanelHeight(Math.max(100, Math.min(500, resizeRef.current.startHeight + delta)));
    };
    const handleMouseUp = () => {
      resizeRef.current = null;
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };
    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  }, [logPanelHeight]);

  // ElapsedTimer components handle their own 1-second re-renders individually.
  // No top-level setTick needed — this avoids re-rendering the entire view every second.

  // Retry: confirm, then dispatch a new task, then remove the old failed one
  const handleRetry = useCallback(async (failedTask: MappedTask) => {
    if (!projectDir) return;
    const taskState = useTaskStore.getState();
    const original = taskState.tasks.get(failedTask.id);
    if (!original) return;

    const ok = await confirm({
      title: 'Retry Task',
      description: `Retry "${original.description}" with ${AGENTS[original.toolName].label}?`,
      confirmLabel: 'Retry',
    });
    if (!ok) return;

    taskState.addOrchestrationLog({
      agent: original.toolName,
      level: 'info',
      message: `Retrying: ${original.description}`,
    });

    const newTaskId = await dispatchTask(original.prompt, projectDir, original.toolName);

    if (newTaskId) {
      useTaskStore.getState().removeTask(failedTask.id);
      const ts = useTaskStore.getState();
      const newTask = ts.tasks.get(newTaskId);
      if (newTask) {
        const newTasks = new Map(ts.tasks);
        newTasks.set(newTask.taskId, { ...newTask, role: 'worker' });
        useTaskStore.setState({ tasks: newTasks });
      }
      toast.success('Task retried');
    } else {
      toast.error('Retry failed');
    }
  }, [projectDir, dispatchTask, confirm]);

  // Switch agent: dispatch with a different agent, remove old failed task
  const handleSwitchAgent = useCallback(async (failedTask: MappedTask, newAgent: ToolName) => {
    if (!projectDir) return;
    const taskState = useTaskStore.getState();
    const original = taskState.tasks.get(failedTask.id);
    if (!original) return;

    const ok = await confirm({
      title: 'Switch Agent & Retry',
      description: `Retry "${original.description}" with ${AGENTS[newAgent].label}?`,
      confirmLabel: 'Switch & Retry',
    });
    if (!ok) return;

    taskState.addOrchestrationLog({
      agent: newAgent,
      level: 'info',
      message: `Switching to ${AGENTS[newAgent].label} and retrying: ${original.description}`,
    });

    const newTaskId = await dispatchTask(original.prompt, projectDir, newAgent);

    if (newTaskId) {
      useTaskStore.getState().removeTask(failedTask.id);
      const ts = useTaskStore.getState();
      const newTask = ts.tasks.get(newTaskId);
      if (newTask) {
        const newTasks = new Map(ts.tasks);
        newTasks.set(newTask.taskId, { ...newTask, role: 'worker' });
        useTaskStore.setState({ tasks: newTasks });
      }
      toast.success(`Retried with ${AGENTS[newAgent].label}`);
    } else {
      toast.error('Retry failed');
    }
  }, [projectDir, dispatchTask, confirm]);

  // Delete a failed task (with undo)
  const handleDelete = useCallback((task: MappedTask) => {
    removeTaskWithUndo(task.id, task.title);
  }, []);

  // Drag & Drop handlers
  const handleDragStart = useCallback((e: React.DragEvent, task: MappedTask) => {
    setDragTaskId(task.id);
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', task.id);
  }, []);

  const handleDragOver = useCallback((e: React.DragEvent, col: ColumnKey) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    setDropTarget(col);
  }, []);

  const handleDragLeave = useCallback(() => {
    setDropTarget(null);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent, targetCol: ColumnKey) => {
    e.preventDefault();
    setDropTarget(null);
    const taskId = dragTaskId || e.dataTransfer.getData('text/plain');
    setDragTaskId(null);
    if (!taskId) return;

    // Map column to task status
    const statusMap: Record<ColumnKey, string> = {
      queued: 'pending',
      running: 'running',
      done: 'completed',
    };
    const newStatus = statusMap[targetCol];
    if (!newStatus) return;

    const store = useTaskStore.getState();
    const task = store.tasks.get(taskId);
    if (!task) return;

    const currentCol = mapColumn(task.status);
    if (currentCol === targetCol) return;

    // Only allow valid transitions:
    // - completed/failed → queued (re-queue)
    // - pending → done (manually mark complete)
    const validTransitions: Record<string, string[]> = {
      queued: ['done', 'running'],   // from queued: can go to done
      running: [],                    // from running: cannot drag
      done: ['queued'],              // from done: can go back to queued
    };
    const allowedTargets = validTransitions[currentCol] ?? [];
    if (!allowedTargets.includes(targetCol)) {
      toast.error(`Cannot move ${currentCol} tasks to ${targetCol}`);
      return;
    }

    store.updateTaskStatus(taskId, newStatus as any);
    store.addOrchestrationLog({
      agent: task.toolName,
      level: 'info',
      message: `Task "${task.description}" moved to ${targetCol}`,
    });
  }, [dragTaskId]);

  const mapped: MappedTask[] = useMemo(() => {
    const result: MappedTask[] = [];
    for (const [, task] of tasks) {
      const col = mapColumn(task.status);
      const now = Date.now();
      const elapsed = task.startedAt ? now - task.startedAt : 0;
      const isDone = col === 'done';

      result.push({
        id: task.taskId,
        title: task.description || task.prompt.slice(0, 60),
        prompt: task.prompt,
        agent: task.toolName,
        column: col,
        startedAt: task.startedAt,
        duration: isDone && task.startedAt ? formatDuration(elapsed) : null,
        elapsedMs: elapsed,
        status: task.status,
        role: task.role,
        resultSummary: task.resultSummary,
        lastOutputLine: task.lastOutputLine,
      });
    }
    return result;
  }, [tasks]);

  const byColumn = useMemo(() => {
    const map: Record<ColumnKey, MappedTask[]> = { queued: [], running: [], done: [] };
    for (const t of mapped) {
      map[t.column].push(t);
    }
    return map;
  }, [mapped]);

  // Apply search & filter
  const filteredByColumn = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    const result: Record<ColumnKey, MappedTask[]> = { queued: [], running: [], done: [] };
    for (const col of ['queued', 'running', 'done'] as ColumnKey[]) {
      // Skip entire column if status filter is active and doesn't match
      if (filterStatus !== 'all' && filterStatus !== col) continue;
      for (const t of byColumn[col]) {
        // Agent filter
        if (filterAgent !== 'all' && t.agent !== filterAgent) continue;
        // Text search
        if (q && !t.title.toLowerCase().includes(q) && !t.prompt.toLowerCase().includes(q)) continue;
        result[col].push(t);
      }
    }
    return result;
  }, [byColumn, searchQuery, filterAgent, filterStatus]);

  const hasActiveFilters = searchQuery.trim() !== '' || filterAgent !== 'all' || filterStatus !== 'all';
  const filteredTotal = filteredByColumn.queued.length + filteredByColumn.running.length + filteredByColumn.done.length;

  // Check if this is a decomposition failure (no worker tasks)
  const hasWorkerTasks = mapped.some((t) => t.role === 'worker');
  const isDecompositionFailure = orchestrationPhase === 'failed' && !hasWorkerTasks;

  if (tasks.size === 0 && orchestrationPhase === 'idle') {
    return (
      <div className="flex items-center justify-center h-full">
        <EmptyState
          icon={'\uD83D\uDCCB'}
          title="No tasks yet"
          description="Launch an orchestration to get started"
          action={{ label: 'New Orchestration', onClick: () => useUIStore.getState().setShowSetup(true) }}
        />
      </div>
    );
  }

  // Show DecompositionErrorCard instead of kanban when decomposition fails
  if (isDecompositionFailure) {
    return (
      <>
        {ConfirmDialogElement}
        <DecompositionErrorCard />
      </>
    );
  }

  // Visible log entries (last 100 for performance)
  const visibleLogs = useMemo(
    () => orchestrationLogs.slice(-100),
    [orchestrationLogs],
  );

  return (
    <>
    {ConfirmDialogElement}
    <div className="flex flex-col h-full font-[Inter,sans-serif]">
      {/* Search & Filter bar */}
      <div
        className="flex items-center gap-2 py-2 px-5 shrink-0"
        style={{ borderBottom: `1px solid ${C.border}` }}
      >
        <div className="relative flex-1 max-w-[280px]">
          <input
            type="text"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Search tasks..."
            style={{
              width: '100%',
              padding: '6px 10px 6px 28px',
              borderRadius: 8,
              background: C.surface,
              border: `1px solid ${C.border}`,
              color: C.textPrimary,
              fontSize: 12,
              outline: 'none',
            }}
          />
          <span style={{ position: 'absolute', left: 8, top: '50%', transform: 'translateY(-50%)', fontSize: 12, color: C.textMuted }}>
            🔍
          </span>
        </div>
        <select
          value={filterAgent}
          onChange={(e) => setFilterAgent(e.target.value as ToolName | 'all')}
          style={{
            padding: '6px 10px',
            borderRadius: 8,
            background: C.surface,
            border: `1px solid ${C.border}`,
            color: filterAgent === 'all' ? C.textMuted : C.textPrimary,
            fontSize: 11,
            outline: 'none',
          }}
        >
          <option value="all">All Agents</option>
          <option value="claude">Claude</option>
          <option value="gemini">Gemini</option>
          <option value="codex">Codex</option>
        </select>
        <select
          value={filterStatus}
          onChange={(e) => setFilterStatus(e.target.value as ColumnKey | 'all')}
          style={{
            padding: '6px 10px',
            borderRadius: 8,
            background: C.surface,
            border: `1px solid ${C.border}`,
            color: filterStatus === 'all' ? C.textMuted : C.textPrimary,
            fontSize: 11,
            outline: 'none',
          }}
        >
          <option value="all">All Status</option>
          <option value="queued">Queued</option>
          <option value="running">In Progress</option>
          <option value="done">Done</option>
        </select>
        {hasActiveFilters && (
          <button
            onClick={() => { setSearchQuery(''); setFilterAgent('all'); setFilterStatus('all'); }}
            style={{
              padding: '4px 10px',
              borderRadius: 8,
              background: C.accentSoft,
              color: C.accentText,
              fontSize: 10,
              fontWeight: 600,
              border: 'none',
              cursor: 'pointer',
            }}
          >
            Clear ({filteredTotal}/{mapped.length})
          </button>
        )}
      </div>

      {/* Kanban columns */}
      <div className="flex gap-4 flex-1 min-h-0 p-5">
        {COLUMNS.map((col) => {
          const items = filteredByColumn[col.key];
          const st = STATUS[col.statusKey];

          return (
            <div
              key={col.key}
              onDragOver={(e) => handleDragOver(e, col.key)}
              onDragLeave={handleDragLeave}
              onDrop={(e) => handleDrop(e, col.key)}
              className="flex-1 min-w-[220px] flex flex-col rounded-[20px] overflow-hidden transition-[border-color,background] duration-150"
              style={{
                border: `1px solid ${dropTarget === col.key ? C.accent : C.border}`,
                background: dropTarget === col.key ? C.accentSoft : C.panel,
              }}
            >
              {/* Column header */}
              <div
                className="flex items-center gap-2 py-3.5 px-4"
                style={{ borderBottom: `1px solid ${C.border}` }}
              >
                <StatusDot color={st.dot} />
                <span style={{ fontSize: 13, fontWeight: 600, color: st.text }}>{col.label}</span>
                <Pill bg={st.bg} color={st.text}>
                  {items.length}
                </Pill>
              </div>

              {/* Cards */}
              <ScrollArea style={{ flex: 1, padding: 12 }}>
                <div className="flex flex-col gap-2.5">
                  {items.length === 0 ? (
                    <div
                      style={{
                        padding: '24px 16px',
                        textAlign: 'center',
                        fontSize: 12,
                        color: C.textMuted,
                        border: `1.5px dashed ${C.border}`,
                        borderRadius: 14,
                      }}
                    >
                      {orchestrationPhase === 'idle'
                        ? 'No tasks'
                        : col.key === 'queued'
                          ? 'Waiting for sub-tasks...'
                          : col.key === 'running' && orchestrationPhase === 'decomposing'
                            ? 'Decomposing task...'
                            : 'No tasks'}
                    </div>
                  ) : (
                    items.map((task) => (
                      <TaskCard
                        key={task.id}
                        task={task}
                        selected={selectedTask === task.id}
                        onClick={() => setSelectedTask(task.id)}
                        onRetry={task.status === 'failed' ? handleRetry : undefined}
                        onSwitchAgent={task.status === 'failed' ? handleSwitchAgent : undefined}
                        onDelete={task.status === 'failed' ? handleDelete : undefined}
                        onDragStart={handleDragStart}
                      />
                    ))
                  )}
                </div>
              </ScrollArea>
            </div>
          );
        })}
      </div>

      {/* Activity Log Panel */}
      <div className="shrink-0">
        {/* Toggle bar */}
        <button
          type="button"
          onClick={() => setLogPanelOpen((prev) => !prev)}
          className="w-full flex items-center gap-2 py-1.5 px-5 cursor-pointer font-[Inter,sans-serif]"
          style={{
            background: C.panel,
            borderTop: `1px solid ${C.border}`,
            borderBottom: logPanelOpen ? `1px solid ${C.border}` : 'none',
          }}
        >
          <span
            className="w-1.5 h-1.5 rounded-full shrink-0"
            style={{ background: orchestrationPhase !== 'idle' ? C.amber : C.textMuted }}
          />
          <span className="text-[11px] font-semibold tracking-[0.02em]" style={{ color: C.textSecondary }}>
            Activity Log
          </span>
          {orchestrationLogs.length > 0 && (
            <span
              className="text-[10px] font-semibold px-1.5 py-px rounded-full"
              style={{ background: C.surface, color: C.textMuted }}
            >
              {orchestrationLogs.length}
            </span>
          )}
          <div className="flex-1" />
          {logPanelOpen ? (
            <ChevronDown size={14} style={{ color: C.textMuted }} />
          ) : (
            <ChevronUp size={14} style={{ color: C.textMuted }} />
          )}
        </button>

        {/* Expandable log content */}
        {logPanelOpen && (
          <div className="relative">
            {/* Resize handle */}
            <div
              onMouseDown={handleResizeMouseDown}
              className="absolute top-0 left-0 right-0 h-1 cursor-ns-resize z-10"
            />
            <ScrollArea
              ref={logScrollRef}
              style={{
                height: logPanelHeight,
                background: C.bg,
                padding: '8px 16px',
              }}
            >
              {visibleLogs.length === 0 ? (
                <div
                  style={{
                    padding: '20px 0',
                    textAlign: 'center',
                    fontSize: 12,
                    color: C.textMuted,
                  }}
                >
                  No activity yet. Logs will appear when orchestration starts.
                </div>
              ) : (
                visibleLogs.map((log) => {
                  const dotColor = LOG_COLOR[log.level] ?? C.textSecondary;
                  const agentInfo = AGENTS[log.agent];
                  return (
                    <div
                      key={log.id}
                      className="flex items-start gap-2 py-[3px] font-[family-name:var(--font-mono)] text-[11px] leading-[18px]"
                    >
                      <span className="shrink-0 w-14 text-[10px]" style={{ color: C.textMuted }}>
                        {log.timestamp}
                      </span>
                      <span
                        className="w-1.5 h-1.5 rounded-full shrink-0 mt-1.5"
                        style={{ background: dotColor }}
                      />
                      <span
                        className="w-4 h-4 rounded inline-flex items-center justify-center text-[8px] font-bold text-white shrink-0 mt-px"
                        style={{ background: agentInfo.gradient }}
                      >
                        {agentInfo.letter}
                      </span>
                      <span className="break-words" style={{ color: LOG_COLOR[log.level] ?? C.textPrimary }}>
                        {log.message}
                      </span>
                    </div>
                  );
                })
              )}
            </ScrollArea>
          </div>
        )}
      </div>
    </div>
    </>
  );
}

import { useEffect, useState, useCallback, useMemo } from 'react';
import { C } from '@/lib/theme';
import { AGENTS } from '@/lib/agents';
import { ScrollArea } from '@/components/ui/scroll-area';
import { useTaskStore, type ToolName } from '@/stores/taskStore';
import { useUIStore } from '@/stores/uiStore';
import { DiffReview } from '../../components/review/DiffReview';
import { useWorktree } from '../../hooks/useWorktree';

/* ── Types ─────────────────────────────────────────────── */

interface CodeReviewViewProps {
  onDone: () => void;
}

type WorktreeStatus = 'pending' | 'merged' | 'discarded' | 'error';

/* ── Sub-components ────────────────────────────────────── */

function StatCard({ label, value, color }: { label: string; value: number; color: string }) {
  return (
    <div
      style={{
        flex: 1,
        padding: '16px 14px',
        borderRadius: 14,
        background: C.surface,
        border: `1px solid ${C.border}`,
        textAlign: 'center',
      }}
    >
      <div style={{ fontSize: 24, fontWeight: 700, color, lineHeight: '32px' }}>{value}</div>
      <div style={{ fontSize: 11, color: C.textSecondary, marginTop: 4 }}>{label}</div>
    </div>
  );
}

function CheckIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none" style={{ flexShrink: 0 }}>
      <circle cx="8" cy="8" r="7" stroke={C.green} strokeWidth="1.5" />
      <path d="M5 8l2 2 4-4" stroke={C.green} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

function WarningIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none" style={{ flexShrink: 0 }}>
      <path d="M8 2L14.93 14H1.07L8 2z" stroke={C.amber} strokeWidth="1.3" fill="none" />
      <line x1="8" y1="6.5" x2="8" y2="10" stroke={C.amber} strokeWidth="1.3" strokeLinecap="round" />
      <circle cx="8" cy="12" r="0.6" fill={C.amber} />
    </svg>
  );
}

function ChevronIcon({ expanded }: { expanded: boolean }) {
  return (
    <svg
      width="14"
      height="14"
      viewBox="0 0 14 14"
      fill="none"
      style={{
        flexShrink: 0,
        transform: expanded ? 'rotate(90deg)' : 'rotate(0deg)',
        transition: 'transform 150ms ease',
      }}
    >
      <path d="M5 3l4 4-4 4" stroke={C.textMuted} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

function StatusBadge({ status }: { status: WorktreeStatus }) {
  const config = {
    pending: { label: 'Pending', bg: C.surface, color: C.textMuted, border: C.border },
    merged: { label: 'Merged', bg: C.greenBg, color: C.green, border: C.greenBorder },
    discarded: { label: 'Discarded', bg: C.surface, color: C.textMuted, border: C.border },
    error: { label: 'Error', bg: C.redBg, color: C.red, border: C.border },
  }[status];

  return (
    <span
      style={{
        fontSize: 10,
        fontWeight: 600,
        padding: '2px 8px',
        borderRadius: 6,
        background: config.bg,
        color: config.color,
        border: `1px solid ${config.border}`,
        textTransform: 'uppercase',
        letterSpacing: '0.04em',
      }}
    >
      {config.label}
    </span>
  );
}

/* ── Main Component ────────────────────────────────────── */

export function CodeReviewView({ onDone }: CodeReviewViewProps) {
  const activePlan = useTaskStore((s) => s.activePlan);
  const orchestrationPlan = useTaskStore((s) => s.orchestrationPlan);
  const tasks = useTaskStore((s) => s.tasks);
  const orchestrationLogs = useTaskStore((s) => s.orchestrationLogs);
  const setOrchestrationPhase = useTaskStore((s) => s.setOrchestrationPhase);
  const worktreeEntries = useTaskStore((s) => s.worktreeEntries);

  const projectDir = useUIStore((s) => s.projectDir);
  const { mergeWorktree, cleanupWorktrees } = useWorktree(projectDir);

  // Determine master agent from config or plan
  const masterAgent: ToolName = (orchestrationPlan?.masterAgent as ToolName)
    || (activePlan?.master_agent as ToolName)
    || 'claude';
  const icon = AGENTS[masterAgent];

  // Derive stats from tasks
  const { taskArray, tasksDone, warnings, totalTasks } = useMemo(() => {
    const arr = Array.from(tasks.values());
    let done = 0, failed = 0;
    for (const t of arr) {
      if (t.status === 'completed') done++;
      else if (t.status === 'failed') failed++;
    }
    return { taskArray: arr, tasksDone: done, warnings: failed, totalTasks: arr.length };
  }, [tasks]);

  // Extract review text from orchestration logs
  const reviewLogs = orchestrationLogs.filter(
    l => l.level === 'success' || (l.level === 'info' && l.message.includes('Review complete'))
  );
  const reviewText = reviewLogs.length > 0
    ? reviewLogs.map(l => l.message).join('\n')
    : null;

  // Build task summary rows
  const taskRows = taskArray.map(t => ({
    id: t.taskId,
    description: t.description,
    agent: t.toolName,
    status: t.status,
    isOk: t.status === 'completed',
  }));

  // Per-worktree status tracking
  const [worktreeStatuses, setWorktreeStatuses] = useState<Map<string, WorktreeStatus>>(new Map());
  const [expandedWorktree, setExpandedWorktree] = useState<string | null>(null);
  const [mergeAllInProgress, setMergeAllInProgress] = useState(false);
  const [completing, setCompleting] = useState(false);

  // Initialize worktree statuses when entries arrive
  useEffect(() => {
    if (worktreeEntries.size > 0 && worktreeStatuses.size === 0) {
      const initial = new Map<string, WorktreeStatus>();
      for (const [dagId] of worktreeEntries) {
        initial.set(dagId, 'pending');
      }
      setWorktreeStatuses(initial);
    }
  }, [worktreeEntries, worktreeStatuses.size]);

  const entries = Array.from(worktreeEntries.values());
  const pendingCount = entries.filter(e => (worktreeStatuses.get(e.dagId) ?? 'pending') === 'pending').length;
  const errorCount = entries.filter(e => worktreeStatuses.get(e.dagId) === 'error').length;
  const allHandled = entries.length > 0 && pendingCount === 0 && errorCount === 0;
  const hasWorktrees = worktreeEntries.size > 0;

  const handleWorktreeClose = useCallback((dagId: string, action: 'merged' | 'discarded') => {
    setWorktreeStatuses(prev => {
      const next = new Map(prev);
      next.set(dagId, action);
      return next;
    });
    setExpandedWorktree(null);
  }, []);

  const handleMergeAll = useCallback(async () => {
    setMergeAllInProgress(true);
    try {
      const pendingEntries = entries.filter(e => worktreeStatuses.get(e.dagId) === 'pending');
      for (const entry of pendingEntries) {
        const success = await mergeWorktree(entry.branchName);
        setWorktreeStatuses(prev => {
          const next = new Map(prev);
          next.set(entry.dagId, success ? 'merged' : 'error');
          return next;
        });
      }
    } finally {
      setMergeAllInProgress(false);
    }
  }, [entries, worktreeStatuses, mergeWorktree]);

  const handleComplete = useCallback(async () => {
    setCompleting(true);
    try {
      await cleanupWorktrees();
    } catch {
      // Cleanup failure is non-fatal
    } finally {
      setOrchestrationPhase('completed');
      onDone();
    }
  }, [cleanupWorktrees, setOrchestrationPhase, onDone]);

  const handleDirectComplete = useCallback(() => {
    setOrchestrationPhase('completed');
    onDone();
  }, [setOrchestrationPhase, onDone]);

  return (
    <ScrollArea style={{ height: '100%' }}>
      <div
        style={{
          maxWidth: 720,
          padding: '32px 28px',
          fontFamily: 'Inter, sans-serif',
        }}
      >
        {/* Header — dynamic master agent */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 14, marginBottom: 24 }}>
          <div
            style={{
              width: 36,
              height: 36,
              borderRadius: 10,
              background: icon.gradient,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: 15,
              fontWeight: 700,
              color: '#fff',
              flexShrink: 0,
            }}
          >
            {icon.letter}
          </div>
          <div>
            <h2 style={{ fontSize: 20, fontWeight: 700, color: C.textPrimary, margin: 0 }}>
              Code Review
            </h2>
            <p style={{ fontSize: 12, color: C.textSecondary, marginTop: 2, marginBottom: 0 }}>
              {icon.label} has reviewed all completed work
            </p>
          </div>
        </div>

        {/* Stats grid */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 12, marginBottom: 24 }}>
          <StatCard label="Completed" value={tasksDone} color={C.green} />
          <StatCard label="Total Tasks" value={totalTasks} color={C.accentText} />
          <StatCard label="Warnings" value={warnings} color={C.amber} />
        </div>

        {/* Review summary from master agent */}
        {reviewText && (
          <div
            style={{
              padding: 16,
              borderRadius: 16,
              background: C.surface,
              border: `1px solid ${C.border}`,
              marginBottom: 24,
            }}
          >
            <div
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 8,
                marginBottom: 12,
                fontSize: 11,
                fontWeight: 700,
                color: C.textMuted,
                textTransform: 'uppercase',
                letterSpacing: '0.06em',
              }}
            >
              <div
                style={{
                  width: 18,
                  height: 18,
                  borderRadius: 5,
                  background: icon.gradient,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: 9,
                  fontWeight: 700,
                  color: '#fff',
                }}
              >
                {icon.letter}
              </div>
              {icon.label}&apos;s Review
            </div>
            <div
              style={{
                fontSize: 13,
                color: C.textPrimary,
                lineHeight: '22px',
                whiteSpace: 'pre-wrap',
                fontFamily: 'var(--font-mono)',
              }}
            >
              {reviewText}
            </div>
          </div>
        )}

        {/* Task results table */}
        {taskRows.length > 0 && (
          <div
            style={{
              borderRadius: 16,
              border: `1px solid ${C.border}`,
              overflow: 'hidden',
              marginBottom: 24,
            }}
          >
            <div
              style={{
                display: 'grid',
                gridTemplateColumns: '28px 1fr 1fr',
                gap: 12,
                padding: '10px 16px',
                background: C.surface,
                borderBottom: `1px solid ${C.border}`,
                fontSize: 11,
                fontWeight: 600,
                color: C.textMuted,
                textTransform: 'uppercase',
                letterSpacing: '0.05em',
              }}
            >
              <span />
              <span>Task</span>
              <span>Agent / Status</span>
            </div>
            {taskRows.map((row) => {
              const agentIcon = AGENTS[row.agent] ?? AGENTS.claude;
              return (
                <div
                  key={row.id}
                  style={{
                    display: 'grid',
                    gridTemplateColumns: '28px 1fr 1fr',
                    gap: 12,
                    padding: '12px 16px',
                    borderBottom: `1px solid ${C.border}`,
                    alignItems: 'center',
                  }}
                >
                  {row.isOk ? <CheckIcon /> : <WarningIcon />}
                  <span
                    style={{
                      fontSize: 12,
                      fontFamily: 'var(--font-mono)',
                      color: C.textPrimary,
                      overflow: 'hidden',
                      textOverflow: 'ellipsis',
                      whiteSpace: 'nowrap',
                    }}
                  >
                    {row.description}
                  </span>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                    <div
                      style={{
                        width: 16,
                        height: 16,
                        borderRadius: 4,
                        background: agentIcon.gradient,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: 8,
                        fontWeight: 700,
                        color: '#fff',
                        flexShrink: 0,
                      }}
                    >
                      {agentIcon.letter}
                    </div>
                    <span style={{ fontSize: 12, color: C.textSecondary, lineHeight: '18px' }}>
                      {agentIcon.label} — {row.status}
                    </span>
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {/* ── Per-Worktree Review Section ────────────────── */}
        {hasWorktrees ? (
          <div style={{ marginBottom: 24 }}>
            <div
              style={{
                fontSize: 11,
                fontWeight: 700,
                color: C.textMuted,
                textTransform: 'uppercase',
                letterSpacing: '0.06em',
                marginBottom: 12,
              }}
            >
              Worktree Changes ({entries.length})
            </div>

            {entries.map((entry) => {
              const status = worktreeStatuses.get(entry.dagId) ?? 'pending';
              const isExpanded = expandedWorktree === entry.dagId;
              const isHandled = status !== 'pending';

              return (
                <div
                  key={entry.dagId}
                  style={{
                    borderRadius: 14,
                    border: `1px solid ${C.border}`,
                    marginBottom: 10,
                    overflow: 'hidden',
                    opacity: isHandled ? 0.6 : 1,
                    transition: 'opacity 150ms ease',
                  }}
                >
                  {/* Worktree card header */}
                  <button
                    type="button"
                    onClick={() => setExpandedWorktree(isExpanded ? null : entry.dagId)}
                    disabled={isHandled}
                    style={{
                      width: '100%',
                      display: 'flex',
                      alignItems: 'center',
                      gap: 10,
                      padding: '12px 16px',
                      background: C.surface,
                      border: 'none',
                      cursor: isHandled ? 'default' : 'pointer',
                      textAlign: 'left',
                      fontFamily: 'Inter, sans-serif',
                      transition: 'background 150ms ease',
                      outline: 'revert',
                    }}
                    onMouseEnter={(e) => {
                      if (!isHandled) e.currentTarget.style.background = C.surfaceHover;
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.background = C.surface;
                    }}
                  >
                    <ChevronIcon expanded={isExpanded} />
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontSize: 13, fontWeight: 600, color: C.textPrimary, marginBottom: 2 }}>
                        {entry.branchName}
                      </div>
                      <div style={{ fontSize: 11, color: C.textSecondary, display: 'flex', gap: 10 }}>
                        <span>{entry.fileCount} file{entry.fileCount !== 1 ? 's' : ''}</span>
                        <span style={{ color: C.green }}>+{entry.additions}</span>
                        <span style={{ color: '#f87171' }}>-{entry.deletions}</span>
                      </div>
                    </div>
                    <StatusBadge status={status} />
                  </button>

                  {/* Expanded diff viewer */}
                  {isExpanded && !isHandled && projectDir && (
                    <div style={{ height: 480, borderTop: `1px solid ${C.border}` }}>
                      <DiffReview
                        projectDir={projectDir}
                        branchName={entry.branchName}
                        taskId={entry.dagId}
                        onClose={(action) => handleWorktreeClose(entry.dagId, action)}
                      />
                    </div>
                  )}
                </div>
              );
            })}

            {/* Batch merge controls */}
            <div
              style={{
                display: 'flex',
                justifyContent: 'flex-end',
                gap: 10,
                marginTop: 16,
              }}
            >
              {pendingCount > 0 && (
                <button
                  type="button"
                  onClick={handleMergeAll}
                  disabled={mergeAllInProgress}
                  style={{
                    padding: '8px 20px',
                    borderRadius: 12,
                    background: icon.gradient,
                    border: 'none',
                    color: '#fff',
                    fontSize: 13,
                    fontWeight: 600,
                    cursor: mergeAllInProgress ? 'not-allowed' : 'pointer',
                    fontFamily: 'Inter, sans-serif',
                    boxShadow: '0 8px 24px rgba(109,94,252,0.28)',
                    opacity: mergeAllInProgress ? 0.6 : 1,
                    transition: 'all 150ms ease',
                  }}
                  onMouseEnter={(e) => {
                    if (!mergeAllInProgress) e.currentTarget.style.filter = 'brightness(1.1)';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.filter = 'brightness(1)';
                  }}
                >
                  {mergeAllInProgress ? 'Merging…' : `Merge All (${pendingCount})`}
                </button>
              )}

              {allHandled && (
                <button
                  type="button"
                  onClick={handleComplete}
                  disabled={completing}
                  style={{
                    padding: '8px 20px',
                    borderRadius: 12,
                    background: C.green,
                    border: 'none',
                    color: '#fff',
                    fontSize: 13,
                    fontWeight: 600,
                    cursor: completing ? 'not-allowed' : 'pointer',
                    fontFamily: 'Inter, sans-serif',
                    opacity: completing ? 0.6 : 1,
                    transition: 'all 150ms ease',
                  }}
                >
                  {completing ? 'Cleaning up…' : 'Done'}
                </button>
              )}
            </div>
          </div>
        ) : (
          /* ── Zero worktreeEntries: direct completion path ── */
          <div style={{ marginBottom: 24 }}>
            <div
              style={{
                padding: 16,
                borderRadius: 16,
                background: C.surface,
                border: `1px solid ${C.border}`,
                textAlign: 'center',
              }}
            >
              <p style={{ fontSize: 13, color: C.textSecondary, margin: 0, marginBottom: 12 }}>
                No file changes to review
              </p>
              <button
                type="button"
                onClick={handleDirectComplete}
                style={{
                  padding: '8px 20px',
                  borderRadius: 12,
                  background: icon.gradient,
                  border: 'none',
                  color: '#fff',
                  fontSize: 13,
                  fontWeight: 600,
                  cursor: 'pointer',
                  fontFamily: 'Inter, sans-serif',
                  boxShadow: '0 8px 24px rgba(109,94,252,0.28)',
                  transition: 'all 150ms ease',
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.filter = 'brightness(1.1)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.filter = 'brightness(1)';
                }}
              >
                Complete
              </button>
            </div>
          </div>
        )}
      </div>
    </ScrollArea>
  );
}

import { useState, useEffect, useRef } from 'react';
import { listen } from '@tauri-apps/api/event';
import { C, STATUS, LOG_COLOR } from '@/lib/theme';
import { AGENTS } from '@/lib/agents';
import { ScrollArea } from '@/components/ui/scroll-area';
import { useTaskStore, type ToolName } from '@/stores/taskStore';
import { useProcessStore, registerProcessOutput, unregisterProcessOutput } from '@/hooks/useProcess';
import type { OutputEvent } from '@/bindings';
import { commands } from '@/bindings';
import { EmptyState } from '@/components/shared/EmptyState';

/* ── Types ─────────────────────────────────────────────── */

type TerminalMode = 'orchestration' | 'standalone';

interface TerminalViewProps {
  devMode: boolean;
}

interface MergeQueueItem {
  branch: string;
  agent: ToolName;
  status: 'ready' | 'merging' | 'merged';
}

interface StandaloneOutput {
  id: string;
  text: string;
  stream: 'stdout' | 'stderr' | 'system';
}

/* ── Constants ─────────────────────────────────────────── */

/* ── Helpers ───────────────────────────────────────────── */

function mergeStatusStyle(status: MergeQueueItem['status']): { bg: string; text: string; label: string } {
  switch (status) {
    case 'ready':
      return { bg: C.amberBg, text: C.amber, label: 'Ready' };
    case 'merging':
      return { bg: C.accentSoft, text: C.accentText, label: 'Merging' };
    case 'merged':
      return { bg: C.greenBg, text: C.green, label: 'Merged' };
  }
}

/* ── Main Component ────────────────────────────────────── */

export function TerminalView({ devMode }: TerminalViewProps) {
  const tasks = useTaskStore((s) => s.tasks);
  const logs = useTaskStore((s) => s.orchestrationLogs);
  const addLog = useTaskStore((s) => s.addOrchestrationLog);
  const orchestrationPhase = useTaskStore((s) => s.orchestrationPhase);
  const activePlan = useTaskStore((s) => s.activePlan);
  const [devInput, setDevInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);
  const standaloneScrollRef = useRef<HTMLDivElement>(null);

  // Terminal mode: orchestration (log view) or standalone (process output)
  const [mode, setMode] = useState<TerminalMode>('orchestration');
  const [standaloneLines, setStandaloneLines] = useState<StandaloneOutput[]>([]);
  const prevPhaseRef = useRef(orchestrationPhase);

  // Auto-switch to standalone when orchestration completes/fails
  useEffect(() => {
    const prev = prevPhaseRef.current;
    prevPhaseRef.current = orchestrationPhase;
    if (
      (prev === 'executing' || prev === 'reviewing') &&
      (orchestrationPhase === 'completed' || orchestrationPhase === 'failed')
    ) {
      setMode('standalone');
    }
    // Auto-switch to orchestration when a new orchestration starts
    if (prev === 'idle' && orchestrationPhase === 'decomposing') {
      setMode('orchestration');
    }
  }, [orchestrationPhase]);

  // Subscribe to active process output for standalone mode
  const activeProcessId = useProcessStore((s) => s.activeProcessId);
  useEffect(() => {
    if (mode !== 'standalone' || !activeProcessId) return;
    setStandaloneLines([]);
    const handler = (event: OutputEvent) => {
      let text = '';
      let stream: StandaloneOutput['stream'] = 'stdout';
      if (event.event === 'stdout') {
        text = event.data;
        stream = 'stdout';
      } else if (event.event === 'stderr') {
        text = event.data;
        stream = 'stderr';
      } else if (event.event === 'error') {
        text = `Error: ${event.data}`;
        stream = 'stderr';
      } else if (event.event === 'exit') {
        text = `Process exited with code ${event.data}`;
        stream = 'system';
      }
      if (!text) return;
      setStandaloneLines((prev) => [
        ...prev.slice(-999),
        { id: `${Date.now()}-${Math.random().toString(36).slice(2, 6)}`, text, stream },
      ]);
    };
    registerProcessOutput(activeProcessId, handler);
    return () => unregisterProcessOutput(activeProcessId);
  }, [mode, activeProcessId]);

  // Auto-scroll standalone output
  useEffect(() => {
    if (standaloneScrollRef.current) {
      standaloneScrollRef.current.scrollTop = standaloneScrollRef.current.scrollHeight;
    }
  }, [standaloneLines.length]);

  // Auto-scroll to bottom on new logs
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [logs.length]);

  // Subscribe to orchestration output events
  useEffect(() => {
    const unlisten = listen<string>('messenger-event', (event) => {
      try {
        const msg = typeof event.payload === 'string' ? JSON.parse(event.payload) : event.payload;
        if (msg.agent && msg.content) {
          const level = msg.message_type?.includes('Failed') ? 'error' as const
            : msg.message_type?.includes('Completed') ? 'success' as const
            : msg.message_type?.includes('Started') || msg.message_type?.includes('Assigned') ? 'cmd' as const
            : 'info' as const;
          addLog({ agent: (msg.agent as ToolName) || 'claude', level, message: msg.content });
        }
      } catch { /* ignore non-JSON */ }
    });
    return () => { unlisten.then(fn => fn()); };
  }, [addLog]);

  // Derive agent statuses from orchestration phase + tasks
  const isRunning = orchestrationPhase !== 'idle' && orchestrationPhase !== 'failed';
  const orchestrationPlan = useTaskStore((s) => s.orchestrationPlan);

  // Master agent: prefer orchestrationPlan (set at launch) over activePlan (set after completion)
  const masterAgent: ToolName = (orchestrationPlan?.masterAgent as ToolName)
    || (activePlan?.master_agent as ToolName)
    || 'claude';

  // Build role-aware agent status from orchestration config + task state
  const configuredAgents = new Set<ToolName>();
  if (orchestrationPlan) {
    for (const a of orchestrationPlan.agents) {
      configuredAgents.add(a.toolName);
    }
  }

  const agents = new Map<ToolName, { status: string; role: string }>();
  for (const [, task] of tasks) {
    const existing = agents.get(task.toolName);
    if (!existing || task.status === 'running') {
      const role = task.toolName === masterAgent ? 'master' : 'worker';
      agents.set(task.toolName, { status: task.status, role });
    }
  }
  // Default agents with orchestration-aware status and roles
  const allAgents: ToolName[] = ['claude', 'gemini', 'codex'];
  for (const name of allAgents) {
    if (!agents.has(name)) {
      const isMaster = name === masterAgent;
      const isInSession = configuredAgents.has(name) || !isRunning;
      const role = isMaster ? 'master' : isInSession ? 'worker' : '';
      const status = isRunning && isMaster ? 'running'
        : isRunning && isInSession ? 'waiting'
        : 'idle';
      agents.set(name, { status, role });
    }
  }

  // Build merge queue from completed tasks
  const mergeQueue: MergeQueueItem[] = [];
  for (const [, task] of tasks) {
    if (task.status === 'completed' || task.status === 'review') {
      mergeQueue.push({
        branch: `wc/${task.toolName}-${task.taskId.slice(0, 6)}`,
        agent: task.toolName,
        status: task.status === 'completed' ? 'merged' : 'ready',
      });
    } else if (task.status === 'running') {
      mergeQueue.push({
        branch: `wc/${task.toolName}-${task.taskId.slice(0, 6)}`,
        agent: task.toolName,
        status: 'merging',
      });
    }
  }

  const agentStatusColor = (status: string): string => {
    if (status === 'running') return C.amber;
    if (status === 'completed') return C.green;
    if (status === 'failed') return C.red;
    return C.textMuted;
  };

  const agentStatusLabel = (status: string, role: string): string => {
    if (status === 'running' && role === 'master') return 'Thinking';
    if (status === 'running' && role === 'worker') return 'Working';
    if (status === 'waiting' && role === 'worker') {
      // Show phase-aware standby message for workers
      if (orchestrationPhase === 'decomposing') return 'Waiting for plan';
      if (orchestrationPhase === 'executing') return 'Queued';
      return 'Standby';
    }
    if (status === 'waiting') return 'Standby';
    const s = STATUS[status];
    return s ? s.label : 'Idle';
  };

  return (
    <div
      style={{
        display: 'flex',
        height: '100%',
        fontFamily: 'Inter, sans-serif',
      }}
    >
      {/* Thinking animation keyframes */}
      <style>{`
        @keyframes thinkPulse {
          0%, 80%, 100% { opacity: 0.3; transform: scale(0.8); }
          40% { opacity: 1; transform: scale(1.2); }
        }
      `}</style>
      {/* ── Left: Agent list ──────────────────────────── */}
      <div
        style={{
          width: 176,
          minWidth: 176,
          borderRight: `1px solid ${C.border}`,
          display: 'flex',
          flexDirection: 'column',
          background: C.sidebar,
        }}
      >
        <div
          style={{
            padding: '14px 16px',
            borderBottom: `1px solid ${C.border}`,
            fontSize: 11,
            fontWeight: 700,
            textTransform: 'uppercase',
            letterSpacing: '0.08em',
            color: C.textMuted,
          }}
        >
          Agents
        </div>
        <ScrollArea style={{ flex: 1 }}>
          <div style={{ padding: 8, display: 'flex', flexDirection: 'column', gap: 4 }}>
            {Array.from(agents.entries()).map(([name, info]) => {
              const icon = AGENTS[name];
              const isAgentRunning = info.status === 'running';
              const isWaiting = info.status === 'waiting';
              const notInSession = isRunning && !info.role;
              return (
                <div
                  key={name}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 10,
                    padding: '10px 12px',
                    borderRadius: 12,
                    background: isAgentRunning ? C.accentSoft : C.surface,
                    border: `1px solid ${isAgentRunning ? C.accent + '60' : C.border}`,
                    transition: 'all 0.3s',
                    opacity: notInSession ? 0.4 : 1,
                  }}
                >
                  <div
                    style={{
                      width: 24,
                      height: 24,
                      borderRadius: 7,
                      background: icon.gradient,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      fontSize: 11,
                      fontWeight: 700,
                      color: '#fff',
                      flexShrink: 0,
                    }}
                  >
                    {icon.letter}
                  </div>
                  <div style={{ minWidth: 0, flex: 1 }}>
                    <div
                      style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: 6,
                        lineHeight: '16px',
                      }}
                    >
                      <span style={{ fontSize: 12, fontWeight: 600, color: C.textPrimary }}>
                        {AGENTS[name].label}
                      </span>
                      {info.role && isRunning && (
                        <span style={{
                          fontSize: 8,
                          fontWeight: 700,
                          textTransform: 'uppercase',
                          letterSpacing: '0.05em',
                          padding: '1px 5px',
                          borderRadius: 4,
                          background: info.role === 'master' ? C.accent + '30' : C.borderStrong,
                          color: info.role === 'master' ? C.accentText : C.textMuted,
                        }}>
                          {info.role}
                        </span>
                      )}
                    </div>
                    <div
                      style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: 5,
                        marginTop: 3,
                      }}
                    >
                      {isAgentRunning ? (
                        <div style={{ display: 'flex', alignItems: 'center', gap: 3 }}>
                          {[0, 1, 2].map((i) => (
                            <span
                              key={i}
                              className="thinking-dot"
                              style={{
                                width: 4,
                                height: 4,
                                borderRadius: '50%',
                                background: C.accent,
                                animation: `thinkPulse 1.2s ease-in-out ${i * 0.2}s infinite`,
                              }}
                            />
                          ))}
                          <span style={{ fontSize: 10, color: C.accentText, marginLeft: 3, fontWeight: 500 }}>
                            {agentStatusLabel(info.status, info.role)}
                          </span>
                        </div>
                      ) : isWaiting ? (
                        <div style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
                          <span style={{ width: 6, height: 6, borderRadius: '50%', background: C.amber, flexShrink: 0, opacity: 0.6 }} />
                          <span style={{ fontSize: 10, color: C.amber, opacity: 0.8 }}>
                            {agentStatusLabel(info.status, info.role)}
                          </span>
                        </div>
                      ) : (
                        <>
                          <span
                            style={{
                              width: 6,
                              height: 6,
                              borderRadius: '50%',
                              background: agentStatusColor(info.status),
                              flexShrink: 0,
                            }}
                          />
                          <span style={{ fontSize: 10, color: C.textSecondary }}>
                            {agentStatusLabel(info.status, info.role)}
                          </span>
                        </>
                      )}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </ScrollArea>
      </div>

      {/* ── Center: Terminal output ────────────────────── */}
      <div
        style={{
          flex: 1,
          display: 'flex',
          flexDirection: 'column',
          minWidth: 0,
          background: '#08080f',
        }}
      >
        {/* Header with mode tabs */}
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: 8,
            padding: '8px 16px',
            borderBottom: `1px solid ${C.border}`,
            background: C.panel,
          }}
        >
          <span style={{ width: 12, height: 12, borderRadius: '50%', background: '#ef4444' }} />
          <span style={{ width: 12, height: 12, borderRadius: '50%', background: '#eab308' }} />
          <span style={{ width: 12, height: 12, borderRadius: '50%', background: '#22c55e' }} />
          <div style={{ marginLeft: 12, display: 'flex', gap: 2, background: C.surface, borderRadius: 8, padding: 2 }}>
            {(['orchestration', 'standalone'] as const).map((m) => (
              <button
                key={m}
                onClick={() => setMode(m)}
                style={{
                  padding: '4px 12px',
                  borderRadius: 6,
                  border: 'none',
                  cursor: 'pointer',
                  fontSize: 11,
                  fontWeight: 600,
                  fontFamily: 'var(--font-mono)',
                  background: mode === m ? C.accent + '30' : 'transparent',
                  color: mode === m ? C.accentText : C.textMuted,
                  transition: 'all 0.15s',
                }}
              >
                {m === 'orchestration' ? 'Orchestration' : 'Standalone'}
              </button>
            ))}
          </div>
          {mode === 'standalone' && activeProcessId && (
            <span style={{ fontSize: 10, color: C.textMuted, marginLeft: 'auto', fontFamily: 'var(--font-mono)' }}>
              pid:{activeProcessId.slice(0, 8)}
            </span>
          )}
        </div>

        {/* Orchestration mode: log lines */}
        {mode === 'orchestration' && (
          <ScrollArea ref={scrollRef} style={{ flex: 1, padding: 16 }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
              {logs.length === 0 && (
                <EmptyState
                  icon={'\uD83D\uDCBB'}
                  title="No output yet"
                  description="Terminal output will appear when a task starts"
                />
              )}
              {logs.map((line) => {
                const dotColor = LOG_COLOR[line.level] ?? C.textSecondary;
                const icon = AGENTS[line.agent];
                return (
                  <div
                    key={line.id}
                    style={{
                      display: 'flex',
                      alignItems: 'flex-start',
                      gap: 10,
                      padding: '6px 0',
                      fontFamily: 'var(--font-mono)',
                      fontSize: 12,
                      lineHeight: '20px',
                    }}
                  >
                    <span style={{ color: C.textMuted, flexShrink: 0, width: 62 }}>
                      {line.timestamp}
                    </span>
                    <span
                      style={{
                        width: 7,
                        height: 7,
                        borderRadius: '50%',
                        background: dotColor,
                        flexShrink: 0,
                        marginTop: 6,
                      }}
                    />
                    <span
                      style={{
                        width: 18,
                        height: 18,
                        borderRadius: 5,
                        background: icon.gradient,
                        display: 'inline-flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: 9,
                        fontWeight: 700,
                        color: '#fff',
                        flexShrink: 0,
                      }}
                    >
                      {icon.letter}
                    </span>
                    <span style={{ color: C.textPrimary }}>{line.message}</span>
                  </div>
                );
              })}
            </div>
          </ScrollArea>
        )}

        {/* Standalone mode: raw process output */}
        {mode === 'standalone' && (
          <ScrollArea ref={standaloneScrollRef} style={{ flex: 1, padding: 16 }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
              {standaloneLines.length === 0 && !activeProcessId && (
                <EmptyState
                  icon={'\u2328\uFE0F'}
                  title="No active process"
                  description="Start a task to see its output here"
                />
              )}
              {standaloneLines.length === 0 && activeProcessId && (
                <EmptyState
                  icon={'\u23F3'}
                  title="Waiting for output"
                  description="Process is running, output will appear shortly"
                />
              )}
              {standaloneLines.map((line) => (
                <div
                  key={line.id}
                  style={{
                    fontFamily: 'var(--font-mono)',
                    fontSize: 12,
                    lineHeight: '20px',
                    padding: '1px 0',
                    color: line.stream === 'stderr' ? C.red
                      : line.stream === 'system' ? C.textMuted
                      : C.textPrimary,
                    whiteSpace: 'pre-wrap',
                    wordBreak: 'break-all',
                  }}
                >
                  {line.text}
                </div>
              ))}
            </div>
          </ScrollArea>
        )}

        {/* Dev mode input bar */}
        {devMode && (
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 10,
              padding: '10px 16px',
              borderTop: `1px solid ${C.border}`,
              background: C.panel,
            }}
          >
            <span style={{ color: C.accent, fontSize: 14, fontWeight: 700 }}>$</span>
            <input
              type="text"
              value={devInput}
              onChange={(e) => setDevInput(e.target.value)}
              onKeyDown={async (e) => {
                if (e.key === 'Enter' && devInput.trim()) {
                  const input = devInput.trim();
                  setDevInput('');

                  // Find an active running process to send to.
                  // Priority: 1) master process (if still alive), 2) any running process
                  const plan = useTaskStore.getState().activePlan;
                  let processId = plan?.master_process_id ?? null;
                  let agentName: ToolName = (plan?.master_agent as ToolName) || 'claude';

                  // Check if the master process is still running, if not find another
                  const processes = useProcessStore.getState().processes;
                  if (processId && (!processes.has(processId) || processes.get(processId)?.status !== 'running')) {
                    processId = null; // Master is dead, look for alternatives
                  }

                  // Find the most recent running process if master is unavailable
                  if (!processId) {
                    let latestStart = 0;
                    for (const [id, proc] of processes) {
                      if (proc.status === 'running' && proc.startedAt > latestStart) {
                        processId = id;
                        latestStart = proc.startedAt;
                        // Extract agent name from cmd prefix (e.g., "claude: ...")
                        const cmdAgent = proc.cmd.split(':')[0] as ToolName;
                        if (['claude', 'gemini', 'codex'].includes(cmdAgent)) {
                          agentName = cmdAgent;
                        }
                      }
                    }
                  }

                  if (!processId) {
                    addLog({ agent: agentName, level: 'warn', message: 'No running process. All tasks have completed. Use "+ New Task" to start a new one.' });
                    return;
                  }

                  // Echo the command in terminal
                  addLog({ agent: agentName, level: 'cmd', message: `$ ${input}` });

                  try {
                    const result = await commands.sendToProcess(processId, input);
                    if (result.status === 'error') {
                      addLog({ agent: agentName, level: 'error', message: `Send failed: ${result.error}` });
                    }
                  } catch (err) {
                    addLog({ agent: agentName, level: 'error', message: `Send failed: ${err}` });
                  }
                }
              }}
              placeholder="Type a command..."
              style={{
                flex: 1,
                background: 'transparent',
                border: 'none',
                outline: 'none',
                color: C.textPrimary,
                fontSize: 13,
                fontFamily: 'var(--font-mono)',
              }}
            />
          </div>
        )}
      </div>

      {/* ── Right: Merge queue ────────────────────────── */}
      <div
        style={{
          width: 240,
          minWidth: 240,
          borderLeft: `1px solid ${C.border}`,
          display: 'flex',
          flexDirection: 'column',
          background: C.sidebar,
        }}
      >
        <div
          style={{
            padding: '14px 16px',
            borderBottom: `1px solid ${C.border}`,
            fontSize: 11,
            fontWeight: 700,
            textTransform: 'uppercase',
            letterSpacing: '0.08em',
            color: C.textMuted,
          }}
        >
          Merge Queue
        </div>
        <ScrollArea style={{ flex: 1 }}>
          <div style={{ padding: 10, display: 'flex', flexDirection: 'column', gap: 8 }}>
            {mergeQueue.length === 0 && (
              <div style={{ padding: 12, fontSize: 12, color: C.textMuted, textAlign: 'center' }}>
                No branches in queue
              </div>
            )}
            {mergeQueue.map((item) => {
              const ms = mergeStatusStyle(item.status);
              const icon = AGENTS[item.agent];
              return (
                <div
                  key={item.branch}
                  style={{
                    padding: 12,
                    borderRadius: 14,
                    background: C.surface,
                    border: `1px solid ${C.border}`,
                    display: 'flex',
                    flexDirection: 'column',
                    gap: 8,
                  }}
                >
                  <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                    <div
                      style={{
                        width: 20,
                        height: 20,
                        borderRadius: 6,
                        background: icon.gradient,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: 10,
                        fontWeight: 700,
                        color: '#fff',
                        flexShrink: 0,
                      }}
                    >
                      {icon.letter}
                    </div>
                    <span
                      style={{
                        fontSize: 11,
                        fontFamily: 'var(--font-mono)',
                        color: C.textPrimary,
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        whiteSpace: 'nowrap',
                      }}
                    >
                      {item.branch}
                    </span>
                  </div>
                  <span
                    style={{
                      display: 'inline-flex',
                      alignSelf: 'flex-start',
                      alignItems: 'center',
                      gap: 5,
                      padding: '2px 10px',
                      borderRadius: 999,
                      background: ms.bg,
                      color: ms.text,
                      fontSize: 11,
                      fontWeight: 600,
                    }}
                  >
                    <span
                      style={{
                        width: 6,
                        height: 6,
                        borderRadius: '50%',
                        background: ms.text,
                      }}
                    />
                    {ms.label}
                  </span>
                </div>
              );
            })}
          </div>
        </ScrollArea>
      </div>
    </div>
  );
}

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { ChevronUp, ChevronDown, Plus, FileCode2, GitBranch } from 'lucide-react';
import { toast } from 'sonner';
import { C } from '@/lib/theme';
import { AGENTS } from '@/lib/agents';
import { useTaskStore, type ToolName } from '@/stores/taskStore';
import { useUIStore } from '@/stores/uiStore';
import { commands } from '@/bindings';

const AGENT_OPTIONS: ToolName[] = ['claude', 'gemini', 'codex'];

/** Extract file-like tokens from a prompt string (e.g., src/foo.ts, lib/bar.rs) */
function extractFilePills(text: string): string[] {
  const filePattern = /(?:^|\s)((?:[\w./-]+\/)?[\w.-]+\.(?:ts|tsx|js|jsx|rs|py|go|java|css|html|json|toml|yaml|yml|md|sql|sh))\b/g;
  const matches = new Set<string>();
  let m: RegExpExecArray | null;
  while ((m = filePattern.exec(text)) !== null) {
    matches.add(m[1]);
  }
  return Array.from(matches).slice(0, 5); // limit to 5 pills
}

interface EditableTask {
  id: string;
  description: string;
  prompt: string;
  agent: ToolName;
  removed: boolean;
  dependsOn: string | null;
}

export function TaskApprovalView() {
  const tasks = useTaskStore((s) => s.tasks);
  const activePlan = useTaskStore((s) => s.activePlan);
  const orchestrationPhase = useTaskStore((s) => s.orchestrationPhase);
  const autoApprove = useUIStore((s) => s.autoApprove);
  const setAutoApprove = useUIStore((s) => s.setAutoApprove);
  const [approving, setApproving] = useState(false);
  const [visible, setVisible] = useState(false);
  const [showAddForm, setShowAddForm] = useState(false);
  const [newTaskPrompt, setNewTaskPrompt] = useState('');
  const [newTaskAgent, setNewTaskAgent] = useState<ToolName>('claude');
  const addInputRef = useRef<HTMLTextAreaElement>(null);

  // Get worker tasks that are pending approval
  const workerTasks = useMemo(() => {
    const workers: EditableTask[] = [];
    for (const [id, task] of tasks) {
      if (task.role === 'worker' && task.status === 'pending') {
        workers.push({
          id,
          description: task.description,
          prompt: task.prompt,
          agent: task.toolName,
          removed: false,
          dependsOn: task.dependsOn,
        });
      }
    }
    return workers;
  }, [tasks]);

  const [editedTasks, setEditedTasks] = useState<EditableTask[] | null>(null);
  const displayTasks = editedTasks ?? workerTasks;

  // Sync editedTasks when new worker tasks arrive during approval phase.
  // Without this, only the first task_assigned event populates the list.
  useEffect(() => {
    if (orchestrationPhase === 'awaiting_approval' && workerTasks.length > 0) {
      setEditedTasks(prev => {
        // If no edits yet, or if new tasks arrived that aren't in the edit list
        if (!prev || prev.length < workerTasks.length) {
          // Preserve any user edits on existing tasks, append new ones
          const existingIds = new Set(prev?.map(t => t.id) ?? []);
          const preserved = prev ?? [];
          const newTasks = workerTasks.filter(t => !existingIds.has(t.id));
          return [...preserved, ...newTasks];
        }
        return prev;
      });
    }
  }, [orchestrationPhase, workerTasks]);

  // Animate modal entry
  const isOpen = orchestrationPhase === 'awaiting_approval' && displayTasks.length > 0;
  const [countdown, setCountdown] = useState<number | null>(null);

  useEffect(() => {
    if (isOpen) {
      requestAnimationFrame(() => setVisible(true));
      // Start countdown only if auto-approve is enabled
      if (autoApprove) {
        setCountdown(5);
      }
    } else {
      setVisible(false);
      setCountdown(null);
      setEditedTasks(null); // Reset for next session
    }
  }, [isOpen, autoApprove]);

  // Countdown timer — auto-approves when reaching 0
  useEffect(() => {
    if (countdown === null || countdown <= 0) return;
    const timer = setTimeout(() => setCountdown(countdown - 1), 1000);
    return () => clearTimeout(timer);
  }, [countdown]);

  // Auto-approve when countdown reaches 0
  useEffect(() => {
    if (countdown === 0 && isOpen && !approving) {
      handleApprove();
    }
  }, [countdown, isOpen, approving]); // eslint-disable-line react-hooks/exhaustive-deps

  // Focus the add-task textarea when form opens
  useEffect(() => {
    if (showAddForm && addInputRef.current) {
      addInputRef.current.focus();
    }
  }, [showAddForm]);

  const handleAgentChange = useCallback((idx: number, newAgent: ToolName) => {
    setCountdown(null); // Cancel auto-approve on edit
    setEditedTasks(prev => {
      if (!prev) return prev;
      const next = [...prev];
      next[idx] = { ...next[idx], agent: newAgent };
      // Also update in task store
      useTaskStore.getState().updateTaskAgent(next[idx].id, newAgent);
      return next;
    });
  }, []);

  const handleToggleRemove = useCallback((idx: number) => {
    setCountdown(null);
    setEditedTasks(prev => {
      if (!prev) return prev;
      const next = [...prev];
      next[idx] = { ...next[idx], removed: !next[idx].removed };
      return next;
    });
  }, []);

  const handleMoveUp = useCallback((idx: number) => {
    setCountdown(null);
    if (idx === 0) return;
    setEditedTasks(prev => {
      if (!prev) return prev;
      const next = [...prev];
      [next[idx - 1], next[idx]] = [next[idx], next[idx - 1]];
      return next;
    });
  }, []);

  const handleMoveDown = useCallback((idx: number) => {
    setCountdown(null);
    setEditedTasks(prev => {
      if (!prev) return prev;
      if (idx >= prev.length - 1) return prev;
      const next = [...prev];
      [next[idx], next[idx + 1]] = [next[idx + 1], next[idx]];
      return next;
    });
  }, []);

  const handleAddTask = useCallback(() => {
    setCountdown(null);
    if (!newTaskPrompt.trim()) return;
    const newId = `user-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
    const desc = newTaskPrompt.trim();

    // Add to task store
    useTaskStore.getState().addTask({
      taskId: newId,
      prompt: desc,
      toolName: newTaskAgent,
      status: 'pending',
      description: desc.length > 60 ? desc.slice(0, 57) + '...' : desc,
      startedAt: null,
      dependsOn: null,
      role: 'worker',
    });

    // Add to local edited list
    setEditedTasks(prev => [
      ...(prev ?? []),
      { id: newId, description: desc, prompt: desc, agent: newTaskAgent, removed: false, dependsOn: null },
    ]);

    setNewTaskPrompt('');
    setNewTaskAgent('claude');
    setShowAddForm(false);
    toast.success('Sub-task added');
  }, [newTaskPrompt, newTaskAgent]);

  const handleApprove = useCallback(async () => {
    if (!activePlan || approving) return;
    setApproving(true);
    try {
      // Remove tasks that were marked for removal
      const removedIds = displayTasks.filter(t => t.removed).map(t => t.id);
      for (const id of removedIds) {
        useTaskStore.getState().removeTask(id);
      }

      // Build modified task list for backend
      const modifiedTasks = displayTasks
        .filter(t => !t.removed)
        .map(t => ({
          agent: t.agent,
          prompt: t.prompt,
          description: t.description.length > 60 ? t.description.slice(0, 57) + '...' : t.description,
          depends_on: t.dependsOn ? [t.dependsOn] : ([] as string[]),
        }));

      await commands.approveOrchestration(activePlan.task_id, modifiedTasks);
      toast.success('Tasks approved -- execution starting');
    } catch (e) {
      console.error('Approval failed:', e);
      toast.error('Approval failed');
    } finally {
      setApproving(false);
    }
  }, [activePlan, approving, displayTasks]);

  // Dismiss on Escape key
  useEffect(() => {
    if (!isOpen) return;
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        // Cancel auto-approve countdown and hide overlay
        // (overlay stays mounted but pointer-events: none prevents blocking)
        setCountdown(null);
        setVisible(false);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen]);

  if (!isOpen) {
    return null;
  }

  const activeCount = displayTasks.filter(t => !t.removed).length;

  // Compute agent distribution summary
  const agentCounts = new Map<ToolName, number>();
  for (const t of displayTasks) {
    if (!t.removed) {
      agentCounts.set(t.agent, (agentCounts.get(t.agent) ?? 0) + 1);
    }
  }
  const agentSummary = Array.from(agentCounts.entries())
    .map(([agent, count]) => `${count}x ${AGENTS[agent].label.split(' ')[0]}`)
    .join(', ');

  // Build dependency lookup: id -> index (1-based)
  const idToIndex = new Map<string, number>();
  displayTasks.forEach((t, i) => idToIndex.set(t.id, i + 1));

  return (
    <div
      role="dialog"
      aria-modal="true"
      aria-label="Review Sub-Tasks"
      className="fixed inset-0 z-[90] flex items-start justify-center pt-[8vh] transition-[background,backdrop-filter] duration-200 ease-out"
      style={{
        background: visible ? 'rgba(0,0,0,0.5)' : 'rgba(0,0,0,0)',
        backdropFilter: visible ? 'blur(3px)' : 'blur(0px)',
        pointerEvents: visible ? 'auto' : 'none',
      }}
    >
      <div
        className="w-[580px] max-h-[85vh] rounded-[20px] flex flex-col overflow-hidden shadow-[0_20px_60px_rgba(0,0,0,0.7)] transition-[transform,opacity] duration-200 ease-out"
        style={{
          background: C.panel,
          border: `1px solid ${C.borderStrong}`,
          transform: visible ? 'scale(1)' : 'scale(0.95)',
          opacity: visible ? 1 : 0,
        }}
      >
        {/* Header with summary */}
        <div className="pt-5 px-6 pb-4" style={{ borderBottom: `1px solid ${C.border}` }}>
          <div className="flex items-center justify-between">
            <h2 className="m-0 text-base font-bold" style={{ color: C.textPrimary }}>
              Review Sub-Tasks
            </h2>
            {/* Auto-approve toggle */}
            <label className="flex items-center gap-2 cursor-pointer select-none">
              <span className="text-[11px]" style={{ color: C.textMuted }}>Auto-approve</span>
              <button
                type="button"
                onClick={() => setAutoApprove(!autoApprove)}
                className="w-8 h-4 rounded-lg border-none px-0.5 cursor-pointer flex items-center transition-[background] duration-150 ease-in-out"
                style={{ background: autoApprove ? C.accent : C.borderStrong }}
              >
                <div
                  className="w-3 h-3 rounded-full bg-white transition-[margin-left] duration-150 ease-in-out"
                  style={{ marginLeft: autoApprove ? 'auto' : '0' }}
                />
              </button>
            </label>
          </div>

          {/* Summary bar */}
          <div className="mt-2.5 flex items-center gap-2.5">
            <span className="text-xs" style={{ color: C.textSecondary }}>
              {activeCount} task{activeCount !== 1 ? 's' : ''}: {agentSummary}
            </span>
          </div>

          {/* Agent distribution bar */}
          {activeCount > 0 && (
            <div
              className="mt-2 h-1 rounded-sm overflow-hidden flex"
              style={{ background: C.borderStrong }}
            >
              {Array.from(agentCounts.entries()).map(([agent, count]) => (
                <div
                  key={agent}
                  style={{
                    width: `${(count / activeCount) * 100}%`,
                    height: '100%',
                    background: AGENTS[agent].color,
                    transition: 'width 200ms ease',
                  }}
                />
              ))}
            </div>
          )}

          <p className="mt-2 mb-0 text-[11px] leading-4" style={{ color: C.textMuted }}>
            Reorder, reassign agents, add or remove tasks before execution.
          </p>
        </div>

        {/* Task list */}
        <div className="flex-1 overflow-y-auto py-3 px-6">
          {displayTasks.map((task, idx) => {
            const agent = AGENTS[task.agent];
            const filePills = extractFilePills(task.description);
            const depIndex = task.dependsOn ? idToIndex.get(task.dependsOn) : null;

            return (
              <div
                key={task.id}
                className="p-3 py-3 px-3.5 rounded-xl mb-2 transition-all duration-150 ease-in-out"
                style={{
                  background: task.removed ? 'rgba(248,113,113,0.06)' : C.surface,
                  border: `1px solid ${task.removed ? 'rgba(248,113,113,0.2)' : C.border}`,
                  opacity: task.removed ? 0.45 : 1,
                }}
              >
                {/* Top row: reorder + badge + description + controls */}
                <div className="flex items-center gap-2.5">
                  {/* Reorder buttons */}
                  <div className="flex flex-col gap-px shrink-0">
                    <button
                      type="button"
                      onClick={() => handleMoveUp(idx)}
                      disabled={idx === 0}
                      className="w-[18px] h-[14px] rounded-[3px] bg-transparent border-none flex items-center justify-center p-0 transition-colors duration-100 ease-in-out"
                      style={{
                        color: idx === 0 ? C.textMuted + '40' : C.textMuted,
                        cursor: idx === 0 ? 'default' : 'pointer',
                      }}
                      title="Move up"
                    >
                      <ChevronUp size={12} />
                    </button>
                    <button
                      type="button"
                      onClick={() => handleMoveDown(idx)}
                      disabled={idx === displayTasks.length - 1}
                      className="w-[18px] h-[14px] rounded-[3px] bg-transparent border-none flex items-center justify-center p-0 transition-colors duration-100 ease-in-out"
                      style={{
                        color: idx === displayTasks.length - 1 ? C.textMuted + '40' : C.textMuted,
                        cursor: idx === displayTasks.length - 1 ? 'default' : 'pointer',
                      }}
                      title="Move down"
                    >
                      <ChevronDown size={12} />
                    </button>
                  </div>

                  {/* Agent badge with gradient */}
                  <div
                    className="w-[30px] h-[30px] rounded-lg flex items-center justify-center text-xs font-bold text-white shrink-0"
                    style={{ background: agent.gradient }}
                  >
                    {agent.letter}
                  </div>

                  {/* Task content */}
                  <div className="flex-1 min-w-0">
                    {/* Task number */}
                    <div className="flex items-center gap-1.5 mb-0.5">
                      <span className="text-[10px] font-semibold uppercase tracking-[0.04em]" style={{ color: C.textMuted }}>
                        Task {idx + 1} of {displayTasks.length}
                      </span>
                      {depIndex != null && (
                        <span
                          className="text-[9px] font-semibold rounded px-[5px] py-px inline-flex items-center gap-[3px]"
                          style={{
                            color: C.amber,
                            background: C.amberBg,
                            border: `1px solid ${C.amberBorder}`,
                          }}
                        >
                          <GitBranch size={8} />
                          Depends on Task {depIndex}
                        </span>
                      )}
                    </div>
                    {/* Description — editable */}
                    <input
                      type="text"
                      value={task.description}
                      onChange={(e) => {
                        setCountdown(null);
                        setEditedTasks(prev => {
                          if (!prev) return prev;
                          const next = [...prev];
                          next[idx] = { ...next[idx], description: e.target.value };
                          return next;
                        });
                      }}
                      className="text-xs leading-[18px] w-full bg-transparent border-none outline-none p-0"
                      style={{
                        color: task.removed ? C.textMuted : C.textPrimary,
                        textDecoration: task.removed ? 'line-through' : 'none',
                      }}
                      disabled={task.removed}
                    />

                    {/* Full prompt — visible below description */}
                    {!task.removed && task.prompt !== task.description && (
                        <textarea
                          value={task.prompt}
                          onChange={(e) => {
                            setCountdown(null);
                            setEditedTasks(prev => {
                              if (!prev) return prev;
                              const next = [...prev];
                              next[idx] = { ...next[idx], prompt: e.target.value };
                              return next;
                            });
                          }}
                          rows={3}
                          style={{
                            width: '100%',
                            marginTop: 6,
                            padding: '8px 10px',
                            borderRadius: 8,
                            background: C.panel,
                            border: `1px solid ${C.border}`,
                            color: C.textSecondary,
                            fontSize: 11,
                            lineHeight: '16px',
                            fontFamily: 'var(--font-mono)',
                            resize: 'vertical',
                            outline: 'none',
                          }}
                          onFocus={(e) => { e.currentTarget.style.borderColor = C.accent; }}
                          onBlur={(e) => { e.currentTarget.style.borderColor = C.border; }}
                        />
                    )}
                  </div>

                  {/* Agent selector */}
                  {!task.removed && (
                    <select
                      value={task.agent}
                      onChange={(e) => handleAgentChange(idx, e.target.value as ToolName)}
                      style={{
                        padding: '4px 8px',
                        borderRadius: 8,
                        background: C.surfaceHover,
                        border: `1px solid ${C.border}`,
                        color: C.textSecondary,
                        fontSize: 11,
                        fontFamily: 'Inter, sans-serif',
                        cursor: 'pointer',
                        outline: 'none',
                        flexShrink: 0,
                      }}
                    >
                      {AGENT_OPTIONS.map(a => (
                        <option key={a} value={a}>{AGENTS[a].label}</option>
                      ))}
                    </select>
                  )}

                  {/* Remove toggle */}
                  <button
                    type="button"
                    onClick={() => handleToggleRemove(idx)}
                    className="w-7 h-7 rounded-lg border-none text-sm cursor-pointer flex items-center justify-center shrink-0 font-[Inter,sans-serif] transition-all duration-150 ease-in-out"
                    style={{
                      background: task.removed ? 'rgba(74,222,128,0.1)' : 'rgba(248,113,113,0.1)',
                      color: task.removed ? C.green : C.red,
                    }}
                    title={task.removed ? 'Restore task' : 'Remove task'}
                  >
                    {task.removed ? '\u21B6' : '\u2715'}
                  </button>
                </div>

                {/* File pills (scope indicator) */}
                {filePills.length > 0 && !task.removed && (
                  <div className="flex flex-wrap gap-1 mt-2 pl-[58px]">
                    {filePills.map(file => (
                      <span
                        key={file}
                        className="inline-flex items-center gap-[3px] text-[10px] rounded px-1.5 py-px font-[family-name:var(--font-mono)]"
                        style={{
                          color: C.accentText,
                          background: C.accentSoft,
                          border: `1px solid ${C.accent}25`,
                        }}
                      >
                        <FileCode2 size={9} />
                        {file}
                      </span>
                    ))}
                  </div>
                )}
              </div>
            );
          })}

          {/* Add Sub-Task section */}
          {showAddForm ? (
            <div
              className="p-3 py-3 px-3.5 rounded-xl mb-2"
              style={{ background: C.surface, border: `1px dashed ${C.accent}50` }}
            >
              <div className="text-[11px] font-semibold mb-2 uppercase tracking-[0.04em]" style={{ color: C.textMuted }}>
                New Sub-Task
              </div>
              <textarea
                ref={addInputRef}
                value={newTaskPrompt}
                onChange={(e) => setNewTaskPrompt(e.target.value)}
                placeholder="Describe what this task should accomplish..."
                rows={3}
                style={{
                  width: '100%',
                  padding: '8px 10px',
                  borderRadius: 8,
                  background: C.surfaceHover,
                  border: `1px solid ${C.border}`,
                  color: C.textPrimary,
                  fontSize: 12,
                  fontFamily: 'Inter, sans-serif',
                  resize: 'vertical',
                  outline: 'none',
                  lineHeight: '18px',
                  boxSizing: 'border-box',
                }}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && e.metaKey) handleAddTask();
                  if (e.key === 'Escape') setShowAddForm(false);
                }}
              />
              <div className="flex items-center gap-2 mt-2">
                <select
                  value={newTaskAgent}
                  onChange={(e) => setNewTaskAgent(e.target.value as ToolName)}
                  style={{
                    padding: '5px 8px',
                    borderRadius: 8,
                    background: C.surfaceHover,
                    border: `1px solid ${C.border}`,
                    color: C.textSecondary,
                    fontSize: 11,
                    fontFamily: 'Inter, sans-serif',
                    cursor: 'pointer',
                    outline: 'none',
                  }}
                >
                  {AGENT_OPTIONS.map(a => (
                    <option key={a} value={a}>{AGENTS[a].label}</option>
                  ))}
                </select>
                <div className="flex-1" />
                <button
                  type="button"
                  onClick={() => { setShowAddForm(false); setNewTaskPrompt(''); }}
                  className="py-[5px] px-3.5 rounded-lg bg-transparent text-[11px] font-semibold font-[Inter,sans-serif] cursor-pointer transition-all duration-100 ease-in-out"
                  style={{ border: `1px solid ${C.border}`, color: C.textMuted }}
                >
                  Cancel
                </button>
                <button
                  type="button"
                  onClick={handleAddTask}
                  disabled={!newTaskPrompt.trim()}
                  className="py-[5px] px-3.5 rounded-lg border-none text-[11px] font-semibold font-[Inter,sans-serif] transition-all duration-100 ease-in-out"
                  style={{
                    background: newTaskPrompt.trim() ? C.accent : C.borderStrong,
                    color: newTaskPrompt.trim() ? '#fff' : C.textMuted,
                    cursor: newTaskPrompt.trim() ? 'pointer' : 'not-allowed',
                  }}
                >
                  Add
                </button>
              </div>
            </div>
          ) : (
            <button
              type="button"
              onClick={() => setShowAddForm(true)}
              className="w-full py-2.5 px-3.5 rounded-xl bg-transparent text-xs font-medium font-[Inter,sans-serif] cursor-pointer flex items-center justify-center gap-1.5 transition-all duration-150 ease-in-out mb-2"
              style={{ border: `1px dashed ${C.borderStrong}`, color: C.textMuted }}
            >
              <Plus size={14} />
              Add Sub-Task
            </button>
          )}
        </div>

        {/* Footer */}
        <div
          className="py-4 px-6 flex items-center justify-between"
          style={{ borderTop: `1px solid ${C.border}` }}
        >
          <span className="text-xs" style={{ color: C.textMuted }}>
            {activeCount} task{activeCount !== 1 ? 's' : ''} will execute
          </span>
          <button
            type="button"
            disabled={approving || activeCount === 0}
            onClick={handleApprove}
            className="py-2.5 px-7 rounded-xl border-none text-white text-[13px] font-bold font-[Inter,sans-serif] transition-all duration-150 ease-in-out"
            style={{
              background: approving || activeCount === 0 ? C.borderStrong : C.accent,
              cursor: approving || activeCount === 0 ? 'not-allowed' : 'pointer',
            }}
          >
            {approving ? 'Approving...' : countdown !== null && countdown > 0 ? `Auto-starting in ${countdown}s...` : `Approve & Start (${activeCount})`}
          </button>
        </div>
      </div>
    </div>
  );
}

import { useMemo, useState, useCallback, useEffect } from 'react';
import { toast } from 'sonner';
import { RefreshCw, Trash2 } from 'lucide-react';
import { C } from '@/lib/theme';
import { AGENTS } from '@/lib/agents';
import { useTaskStore, type TaskEntry } from '@/stores/taskStore';
import { useUIStore } from '@/stores/uiStore';
import { useTaskDispatch } from '@/hooks/useTaskDispatch';
import { useConfirmDialog } from '@/components/shared/ConfirmDialog';
import { EmptyState } from '@/components/shared/EmptyState';
import { removeTaskWithUndo } from '@/lib/undoableActions';
import { DecompositionErrorCard } from '@/components/orchestration/DecompositionErrorCard';

/* ── Types ─────────────────────────────────────────────── */

interface WorkingViewProps {
  selectedTask: string | null;
  setSelectedTask: (id: string) => void;
}

/* ── Helpers ───────────────────────────────────────────── */

function statusInfo(status: TaskEntry['status']) {
  switch (status) {
    case 'running':
    case 'retrying':
    case 'falling_back':
      return { dot: C.amber, label: 'Running', bg: C.amberBg };
    case 'completed':
    case 'review':
      return { dot: C.green, label: 'Done', bg: C.greenBg };
    case 'failed':
      return { dot: C.red, label: 'Failed', bg: C.redBg };
    case 'blocked':
      return { dot: C.red, label: 'Blocked', bg: C.redBg };
    case 'waiting':
    case 'pending':
    case 'routing':
      return { dot: C.textMuted, label: 'In Queue', bg: C.surface };
    default:
      return { dot: C.textMuted, label: 'Queued', bg: C.surface };
  }
}

function formatElapsed(ms: number): string {
  const s = Math.floor(ms / 1000);
  if (s < 60) return `${s}s`;
  return `${Math.floor(s / 60)}m ${s % 60}s`;
}

/** Leaf component that manages its own 1s timer — avoids re-rendering parent. */
function ElapsedTimer({ startedAt }: { startedAt: number }) {
  const [, setTick] = useState(0);
  useEffect(() => {
    const interval = setInterval(() => setTick((t) => t + 1), 1000);
    return () => clearInterval(interval);
  }, []);
  return <>{formatElapsed(Date.now() - startedAt)}</>;
}

/* ── Main Component ────────────────────────────────────── */

export function WorkingView({ selectedTask, setSelectedTask }: WorkingViewProps) {
  const tasks = useTaskStore((s) => s.tasks);
  const orchestrationPhase = useTaskStore((s) => s.orchestrationPhase);
  const projectDir = useUIStore((s) => s.projectDir);
  const { dispatchTask } = useTaskDispatch();
  const { confirm, ConfirmDialogElement } = useConfirmDialog();

  // Search
  const [searchQuery, setSearchQuery] = useState('');

  // No top-level setTick — ElapsedTimer handles per-task re-renders individually.

  // Build task list
  const taskList = useMemo(() => {
    const result: TaskEntry[] = [];
    for (const [, task] of tasks) {
      if (searchQuery) {
        const q = searchQuery.toLowerCase();
        if (!task.description.toLowerCase().includes(q) && !task.prompt.toLowerCase().includes(q)) continue;
      }
      result.push(task);
    }
    // Sort: running first, then pending, then completed, then failed
    const order: Record<string, number> = { running: 0, retrying: 0, falling_back: 0, pending: 1, routing: 1, waiting: 1, blocked: 2, review: 3, completed: 4, failed: 5 };
    result.sort((a, b) => (order[a.status] ?? 9) - (order[b.status] ?? 9));
    return result;
  }, [tasks, searchQuery]);

  const { runningCount, completedCount, failedCount } = useMemo(() => {
    let running = 0, completed = 0, failed = 0;
    for (const t of taskList) {
      if (t.status === 'running' || t.status === 'retrying') running++;
      else if (t.status === 'completed') completed++;
      else if (t.status === 'failed') failed++;
    }
    return { runningCount: running, completedCount: completed, failedCount: failed };
  }, [taskList]);

  // Retry handler
  const handleRetry = useCallback(async (task: TaskEntry) => {
    if (!projectDir) return;
    const ok = await confirm({
      title: 'Retry Task',
      description: `Retry "${task.description}" with ${AGENTS[task.toolName].label}?`,
      confirmLabel: 'Retry',
    });
    if (!ok) return;
    useTaskStore.getState().addOrchestrationLog({ agent: task.toolName, level: 'info', message: `Retrying: ${task.description}` });
    const newTaskId = await dispatchTask(task.prompt, projectDir, task.toolName);
    if (newTaskId) {
      removeTaskWithUndo(task.taskId, task.description);
      toast.success('Task retried');
    } else {
      toast.error('Retry failed');
    }
  }, [projectDir, dispatchTask, confirm]);

  // Decomposition failure check
  const hasWorkerTasks = taskList.some((t) => t.role === 'worker');
  const isDecompositionFailure = orchestrationPhase === 'failed' && !hasWorkerTasks;

  if (tasks.size === 0 && orchestrationPhase === 'idle') {
    return (
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
        <EmptyState
          icon={'🐋'}
          title="Ready to orchestrate"
          description="Launch an orchestration to get started"
          action={{ label: 'New Orchestration', onClick: () => useUIStore.getState().setShowSetup(true) }}
        />
      </div>
    );
  }

  if (isDecompositionFailure) {
    return (
      <>
        {ConfirmDialogElement}
        <DecompositionErrorCard />
      </>
    );
  }

  return (
    <>
      {ConfirmDialogElement}
      <div style={{ display: 'flex', flexDirection: 'column', height: '100%', fontFamily: 'Inter, sans-serif' }}>
        {/* Header bar */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '8px 20px', borderBottom: `1px solid ${C.border}`, flexShrink: 0 }}>
          {/* Stats */}
          <div style={{ display: 'flex', gap: 12, fontSize: 11 }}>
            {runningCount > 0 && (
              <span style={{ display: 'flex', alignItems: 'center', gap: 4, color: C.amber }}>
                <span style={{ width: 6, height: 6, borderRadius: '50%', background: C.amber }} />
                {runningCount} running
              </span>
            )}
            <span style={{ color: C.textMuted }}>{completedCount}/{taskList.length} done</span>
            {failedCount > 0 && (
              <span style={{ color: C.red }}>{failedCount} failed</span>
            )}
          </div>

          <div style={{ flex: 1 }} />

          {/* Search */}
          <input
            type="text"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Filter tasks..."
            style={{
              width: 200, padding: '5px 10px', borderRadius: 8,
              background: C.surface, border: `1px solid ${C.border}`,
              color: C.textPrimary, fontSize: 11, outline: 'none',
            }}
          />
        </div>

        {/* Task list */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '12px 20px' }}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
            {taskList.map((task) => {
              const si = statusInfo(task.status);
              const isRunning = task.status === 'running' || task.status === 'retrying';
              const isFailed = task.status === 'failed';
              const isDone = task.status === 'completed';
              const isSelected = selectedTask === task.taskId;
              const agent = AGENTS[task.toolName];

              return (
                <button
                  key={task.taskId}
                  type="button"
                  onClick={() => setSelectedTask(task.taskId)}
                  style={{
                    width: '100%', textAlign: 'left',
                    display: 'flex', alignItems: 'center', gap: 12,
                    padding: '12px 14px', borderRadius: 12,
                    background: isSelected ? C.accentSoft : isFailed ? C.redBg : C.surface,
                    border: `1px solid ${isSelected ? C.accent : isFailed ? 'rgba(239,68,68,0.3)' : C.border}`,
                    cursor: 'pointer', transition: 'all 120ms ease',
                    fontFamily: 'Inter, sans-serif',
                  }}
                >
                  {/* Status dot */}
                  <span style={{
                    width: 8, height: 8, borderRadius: '50%',
                    background: si.dot, flexShrink: 0,
                    animation: isRunning ? 'heartbeatPulse 1.5s ease-in-out infinite' : 'none',
                  }} />

                  {/* Agent icon */}
                  <div style={{
                    width: 24, height: 24, borderRadius: 7,
                    background: agent.gradient,
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: 10, fontWeight: 700, color: '#fff', flexShrink: 0,
                  }}>
                    {agent.letter}
                  </div>

                  {/* Content */}
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                      <span style={{
                        fontSize: 13, fontWeight: 600, color: C.textPrimary,
                        overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                      }}>
                        {task.description || task.prompt.slice(0, 60)}
                      </span>
                      {task.role && (
                        <span style={{
                          fontSize: 8, fontWeight: 700, textTransform: 'uppercase', padding: '1px 5px',
                          borderRadius: 4, flexShrink: 0,
                          background: task.role === 'master' ? 'rgba(245,158,11,0.15)' : 'rgba(109,94,252,0.12)',
                          color: task.role === 'master' ? '#f59e0b' : '#8b5cf6',
                        }}>
                          {task.role}
                        </span>
                      )}
                    </div>
                    {/* Live output preview */}
                    {isRunning && task.lastOutputLine && (
                      <div style={{
                        fontSize: 10, color: C.textMuted, marginTop: 3,
                        overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                        fontFamily: 'var(--font-mono)',
                      }}>
                        {task.lastOutputLine}
                      </div>
                    )}
                    {/* Result preview */}
                    {isDone && task.resultSummary && (
                      <div style={{
                        fontSize: 10, color: C.textSecondary, marginTop: 3,
                        overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                      }}>
                        {task.resultSummary.slice(0, 100)}
                      </div>
                    )}
                  </div>

                  {/* Right side — status + elapsed + actions */}
                  <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexShrink: 0 }}>
                    {task.startedAt && (
                      <span style={{ fontSize: 10, color: C.textMuted, fontFamily: 'var(--font-mono)' }}>
                        <ElapsedTimer startedAt={task.startedAt} />
                      </span>
                    )}

                    {isFailed && (
                      <>
                        <button
                          type="button"
                          onClick={(e) => { e.stopPropagation(); handleRetry(task); }}
                          style={{
                            padding: '4px 8px', borderRadius: 6,
                            background: 'rgba(239,68,68,0.12)', border: '1px solid rgba(239,68,68,0.3)',
                            color: '#f87171', fontSize: 10, fontWeight: 600, cursor: 'pointer',
                            display: 'flex', alignItems: 'center', gap: 3,
                          }}
                        >
                          <RefreshCw size={10} /> Retry
                        </button>
                        <button
                          type="button"
                          onClick={(e) => { e.stopPropagation(); removeTaskWithUndo(task.taskId, task.description); }}
                          style={{
                            padding: '4px 6px', borderRadius: 6,
                            background: 'rgba(239,68,68,0.08)', border: '1px solid rgba(239,68,68,0.2)',
                            color: '#f87171', fontSize: 10, cursor: 'pointer',
                            display: 'flex', alignItems: 'center',
                          }}
                        >
                          <Trash2 size={10} />
                        </button>
                      </>
                    )}

                    <span style={{
                      fontSize: 10, fontWeight: 600, padding: '2px 8px',
                      borderRadius: 999, background: si.bg, color: si.dot,
                    }}>
                      {si.label}
                    </span>
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </>
  );
}

import { useState, useCallback, useRef, useEffect } from 'react';
import { AlertTriangle, ChevronDown, ChevronUp, RefreshCw, Pencil, ArrowRightLeft } from 'lucide-react';
import { toast } from 'sonner';
import { C } from '@/lib/theme';
import { AGENTS } from '@/lib/agents';
import { useTaskStore, type ToolName, type OrchestratorConfig } from '@/stores/taskStore';
import { useUIStore } from '@/stores/uiStore';
import { useTaskDispatch } from '@/hooks/useTaskDispatch';
import { humanizeError } from '@/lib/humanizeError';

/**
 * DecompositionErrorCard — shown when orchestrationPhase === 'failed'
 * and no worker tasks exist (failure happened during decomposition).
 *
 * Provides three recovery actions: Retry, Edit & Retry, Switch Agent.
 */
export function DecompositionErrorCard() {
  const orchestrationPhase = useTaskStore((s) => s.orchestrationPhase);
  const tasks = useTaskStore((s) => s.tasks);
  const orchestrationLogs = useTaskStore((s) => s.orchestrationLogs);
  const orchestrationPlan = useTaskStore((s) => s.orchestrationPlan);
  const projectDir = useUIStore((s) => s.projectDir);
  const setShowSetup = useUIStore((s) => s.setShowSetup);
  const { dispatchOrchestratedTask } = useTaskDispatch();

  const [detailsOpen, setDetailsOpen] = useState(false);
  const [agentDropdownOpen, setAgentDropdownOpen] = useState(false);
  const [retrying, setRetrying] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Close agent dropdown on outside click
  useEffect(() => {
    if (!agentDropdownOpen) return;
    function handleClick(e: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setAgentDropdownOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, [agentDropdownOpen]);

  // Determine if this is a decomposition failure
  const hasWorkerTasks = Array.from(tasks.values()).some((t) => t.role === 'worker');
  const isDecompositionFailure = orchestrationPhase === 'failed' && !hasWorkerTasks;

  if (!isDecompositionFailure) return null;

  // Find the master task to get error context
  const masterTask = Array.from(tasks.values()).find((t) => t.role === 'master');
  const masterPrompt = masterTask?.prompt ?? '';

  // Error message: prefer resultSummary, then last error log — humanize for display
  const rawError =
    masterTask?.resultSummary ||
    orchestrationLogs.filter((l) => l.level === 'error').pop()?.message ||
    'The master agent failed to decompose the task into sub-tasks.';
  const errorMessage = humanizeError(rawError);

  // Last N logs for the details section
  const recentLogs = orchestrationLogs.slice(-10);

  // Retry with the same orchestration config
  const handleRetry = useCallback(async () => {
    if (!projectDir || !orchestrationPlan || !masterPrompt || retrying) return;
    setRetrying(true);

    const store = useTaskStore.getState();

    // Clear failed tasks
    for (const [id, t] of store.tasks) {
      if (t.role === 'master' && t.status === 'failed') {
        store.removeTask(id);
      }
    }

    // Reset phase
    store.setOrchestrationPhase('decomposing');
    store.clearOrchestrationLogs();

    // Re-add master task
    const orchTaskId = crypto.randomUUID();
    store.addTask({
      taskId: orchTaskId,
      prompt: masterPrompt,
      toolName: orchestrationPlan.masterAgent,
      status: 'running',
      description: masterPrompt.length > 60 ? masterPrompt.slice(0, 57) + '...' : masterPrompt,
      startedAt: Date.now(),
      dependsOn: null,
      role: 'master',
    });

    store.addOrchestrationLog({ agent: orchestrationPlan.masterAgent, level: 'cmd', message: 'Retrying orchestration...' });

    try {
      await dispatchOrchestratedTask(masterPrompt, projectDir, orchestrationPlan);
    } catch (e) {
      console.error('Retry failed:', e);
      toast.error('Retry failed', { description: String(e) });
      store.addOrchestrationLog({ agent: orchestrationPlan.masterAgent, level: 'error', message: `Retry failed: ${e}` });
      store.setOrchestrationPhase('failed');
    } finally {
      setRetrying(false);
    }
  }, [projectDir, orchestrationPlan, masterPrompt, retrying, dispatchOrchestratedTask]);

  // Open SetupPanel pre-filled (the SetupPanel reads projectDir from uiStore)
  const handleEditAndRetry = useCallback(() => {
    setShowSetup(true);
  }, [setShowSetup]);

  // Switch agent and retry
  const handleSwitchAgent = useCallback(async (newAgent: ToolName) => {
    setAgentDropdownOpen(false);
    if (!projectDir || !orchestrationPlan || !masterPrompt || retrying) return;
    setRetrying(true);

    const store = useTaskStore.getState();

    // Build new config with different master
    const newConfig: OrchestratorConfig = {
      ...orchestrationPlan,
      masterAgent: newAgent,
      agents: orchestrationPlan.agents.map((a) =>
        a.isMaster ? { ...a, toolName: newAgent } : a,
      ),
    };

    // Clear failed tasks
    for (const [id, t] of store.tasks) {
      if (t.role === 'master' && t.status === 'failed') {
        store.removeTask(id);
      }
    }

    // Reset phase
    store.setOrchestrationPhase('decomposing');
    store.setOrchestrationPlan(newConfig);
    store.clearOrchestrationLogs();

    // Re-add master task
    const orchTaskId = crypto.randomUUID();
    store.addTask({
      taskId: orchTaskId,
      prompt: masterPrompt,
      toolName: newAgent,
      status: 'running',
      description: masterPrompt.length > 60 ? masterPrompt.slice(0, 57) + '...' : masterPrompt,
      startedAt: Date.now(),
      dependsOn: null,
      role: 'master',
    });

    store.addOrchestrationLog({ agent: newAgent, level: 'cmd', message: `Retrying with ${AGENTS[newAgent].label} as master...` });

    try {
      await dispatchOrchestratedTask(masterPrompt, projectDir, newConfig);
    } catch (e) {
      console.error('Retry with new agent failed:', e);
      toast.error('Retry failed', { description: String(e) });
      store.addOrchestrationLog({ agent: newAgent, level: 'error', message: `Retry failed: ${e}` });
      store.setOrchestrationPhase('failed');
    } finally {
      setRetrying(false);
    }
  }, [projectDir, orchestrationPlan, masterPrompt, retrying, dispatchOrchestratedTask]);

  // Dismiss the error and reset to idle
  const handleDismiss = useCallback(() => {
    const store = useTaskStore.getState();
    // Clear failed master tasks
    for (const [id, t] of store.tasks) {
      if (t.role === 'master' && t.status === 'failed') {
        store.removeTask(id);
      }
    }
    store.setOrchestrationPhase('idle');
    store.clearOrchestrationLogs();
  }, []);

  const currentMaster = orchestrationPlan?.masterAgent ?? 'claude';
  const otherAgents = (Object.keys(AGENTS) as ToolName[]).filter((a) => a !== currentMaster);

  return (
    <div
      className="decomposition-error-fade-in"
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        height: '100%',
        padding: 32,
        fontFamily: 'Inter, sans-serif',
      }}
    >
      <div
        style={{
          width: '100%',
          maxWidth: 540,
          background: C.surface,
          border: `1.5px solid rgba(248,113,113,0.3)`,
          borderRadius: 24,
          overflow: 'hidden',
        }}
      >
        {/* Header stripe */}
        <div
          style={{
            background: `linear-gradient(135deg, ${C.redBg} 0%, rgba(239,68,68,0.08) 100%)`,
            padding: '28px 32px 24px',
            display: 'flex',
            flexDirection: 'column',
            gap: 16,
          }}
        >
          {/* Icon + title row */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 14 }}>
            <div
              style={{
                width: 44,
                height: 44,
                borderRadius: 14,
                background: 'rgba(248,113,113,0.12)',
                border: '1px solid rgba(248,113,113,0.25)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                flexShrink: 0,
              }}
            >
              <AlertTriangle size={22} color={C.red} />
            </div>
            <div>
              <h3 style={{ fontSize: 17, fontWeight: 700, color: C.textPrimary, margin: 0, lineHeight: '24px' }}>
                Decomposition Failed
              </h3>
              <p style={{ fontSize: 12, color: C.textSecondary, margin: 0, marginTop: 2 }}>
                The master agent could not break down the task
              </p>
            </div>
          </div>

          {/* Error message */}
          <div
            style={{
              padding: '12px 16px',
              borderRadius: 12,
              background: 'rgba(248,113,113,0.06)',
              border: '1px solid rgba(248,113,113,0.15)',
              fontSize: 13,
              lineHeight: '20px',
              color: '#fca5a5',
              wordBreak: 'break-word',
              maxHeight: 120,
              overflow: 'auto',
            }}
          >
            {errorMessage}
          </div>
        </div>

        {/* Actions */}
        <div style={{ padding: '24px 32px', display: 'flex', flexDirection: 'column', gap: 12 }}>
          {/* Retry (primary) */}
          <button
            type="button"
            onClick={handleRetry}
            disabled={retrying}
            style={{
              width: '100%',
              padding: '11px 20px',
              borderRadius: 14,
              background: retrying ? C.accentSoft : C.accent,
              border: 'none',
              color: '#fff',
              fontSize: 13,
              fontWeight: 600,
              fontFamily: 'Inter, sans-serif',
              cursor: retrying ? 'not-allowed' : 'pointer',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: 8,
              transition: 'all 150ms ease',
              opacity: retrying ? 0.7 : 1,
              boxShadow: retrying ? 'none' : '0 0 20px rgba(99,102,241,0.25)',
            }}
          >
            <RefreshCw size={15} className={retrying ? 'animate-spin' : ''} />
            {retrying ? 'Retrying...' : 'Retry'}
          </button>

          {/* Secondary actions row */}
          <div style={{ display: 'flex', gap: 10 }}>
            {/* Edit & Retry */}
            <button
              type="button"
              onClick={handleEditAndRetry}
              style={{
                flex: 1,
                padding: '10px 16px',
                borderRadius: 12,
                background: C.panel,
                border: `1px solid ${C.borderStrong}`,
                color: C.textSecondary,
                fontSize: 12,
                fontWeight: 600,
                fontFamily: 'Inter, sans-serif',
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                gap: 7,
                transition: 'all 150ms ease',
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.background = C.surfaceHover;
                e.currentTarget.style.borderColor = C.accent;
                e.currentTarget.style.color = C.textPrimary;
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.background = C.panel;
                e.currentTarget.style.borderColor = C.borderStrong;
                e.currentTarget.style.color = C.textSecondary;
              }}
            >
              <Pencil size={13} />
              Edit Task & Retry
            </button>

            {/* Switch Agent (dropdown) */}
            <div ref={dropdownRef} style={{ position: 'relative', flex: 1 }}>
              <button
                type="button"
                onClick={() => setAgentDropdownOpen(!agentDropdownOpen)}
                style={{
                  width: '100%',
                  padding: '10px 16px',
                  borderRadius: 12,
                  background: C.panel,
                  border: `1px solid ${agentDropdownOpen ? C.accent : C.borderStrong}`,
                  color: agentDropdownOpen ? C.textPrimary : C.textSecondary,
                  fontSize: 12,
                  fontWeight: 600,
                  fontFamily: 'Inter, sans-serif',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: 7,
                  transition: 'all 150ms ease',
                }}
                onMouseEnter={(e) => {
                  if (!agentDropdownOpen) {
                    e.currentTarget.style.background = C.surfaceHover;
                    e.currentTarget.style.borderColor = C.accent;
                    e.currentTarget.style.color = C.textPrimary;
                  }
                }}
                onMouseLeave={(e) => {
                  if (!agentDropdownOpen) {
                    e.currentTarget.style.background = C.panel;
                    e.currentTarget.style.borderColor = C.borderStrong;
                    e.currentTarget.style.color = C.textSecondary;
                  }
                }}
              >
                <ArrowRightLeft size={13} />
                Switch Agent
              </button>

              {agentDropdownOpen && (
                <div
                  style={{
                    position: 'absolute',
                    top: 'calc(100% + 6px)',
                    left: 0,
                    right: 0,
                    background: C.panel,
                    border: `1px solid ${C.borderStrong}`,
                    borderRadius: 12,
                    overflow: 'hidden',
                    zIndex: 10,
                    boxShadow: '0 8px 32px rgba(0,0,0,0.5)',
                  }}
                >
                  {otherAgents.map((agent) => {
                    const info = AGENTS[agent];
                    return (
                      <button
                        key={agent}
                        type="button"
                        onClick={() => handleSwitchAgent(agent)}
                        style={{
                          width: '100%',
                          display: 'flex',
                          alignItems: 'center',
                          gap: 10,
                          padding: '10px 14px',
                          background: 'transparent',
                          border: 'none',
                          borderBottom: `1px solid ${C.border}`,
                          color: C.textPrimary,
                          fontSize: 12,
                          fontWeight: 500,
                          fontFamily: 'Inter, sans-serif',
                          cursor: 'pointer',
                          transition: 'background 150ms ease',
                        }}
                        onMouseEnter={(e) => { e.currentTarget.style.background = C.surfaceHover; }}
                        onMouseLeave={(e) => { e.currentTarget.style.background = 'transparent'; }}
                      >
                        <div
                          style={{
                            width: 22,
                            height: 22,
                            borderRadius: 7,
                            background: info.gradient,
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            fontSize: 10,
                            fontWeight: 700,
                            color: '#fff',
                            flexShrink: 0,
                          }}
                        >
                          {info.letter}
                        </div>
                        {info.label}
                      </button>
                    );
                  })}
                </div>
              )}
            </div>
          </div>

          {/* Master agent info */}
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 8,
              padding: '8px 12px',
              borderRadius: 10,
              background: C.panel,
              border: `1px solid ${C.border}`,
              fontSize: 11,
              color: C.textMuted,
            }}
          >
            <div
              style={{
                width: 18,
                height: 18,
                borderRadius: 6,
                background: AGENTS[currentMaster].gradient,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: 9,
                fontWeight: 700,
                color: '#fff',
                flexShrink: 0,
              }}
            >
              {AGENTS[currentMaster].letter}
            </div>
            <span>
              Failed with <span style={{ color: C.textSecondary, fontWeight: 500 }}>{AGENTS[currentMaster].label}</span> as master
            </span>
          </div>

          {/* Dismiss */}
          <button
            type="button"
            onClick={handleDismiss}
            style={{
              width: '100%',
              padding: '9px 16px',
              borderRadius: 12,
              background: 'transparent',
              border: `1px solid ${C.border}`,
              color: C.textMuted,
              fontSize: 12,
              fontWeight: 500,
              fontFamily: 'Inter, sans-serif',
              cursor: 'pointer',
              transition: 'all 150ms ease',
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.color = C.textSecondary;
              e.currentTarget.style.borderColor = C.borderStrong;
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.color = C.textMuted;
              e.currentTarget.style.borderColor = C.border;
            }}
          >
            Dismiss
          </button>
        </div>

        {/* Collapsible details */}
        <div style={{ borderTop: `1px solid ${C.border}` }}>
          <button
            type="button"
            onClick={() => setDetailsOpen(!detailsOpen)}
            style={{
              width: '100%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              padding: '12px 32px',
              background: 'transparent',
              border: 'none',
              color: C.textMuted,
              fontSize: 12,
              fontWeight: 600,
              fontFamily: 'Inter, sans-serif',
              cursor: 'pointer',
              transition: 'color 150ms ease',
            }}
            onMouseEnter={(e) => { e.currentTarget.style.color = C.textSecondary; }}
            onMouseLeave={(e) => { e.currentTarget.style.color = C.textMuted; }}
          >
            <span>Orchestration Logs ({recentLogs.length})</span>
            {detailsOpen ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
          </button>

          {detailsOpen && (
            <div
              style={{
                padding: '0 32px 20px',
                display: 'flex',
                flexDirection: 'column',
                gap: 4,
                maxHeight: 220,
                overflowY: 'auto',
              }}
            >
              {recentLogs.length === 0 ? (
                <div style={{ fontSize: 11, color: C.textMuted, padding: '8px 0' }}>
                  No logs available
                </div>
              ) : (
                recentLogs.map((log) => {
                  const levelColor: Record<string, string> = {
                    info: C.textSecondary,
                    success: C.green,
                    warn: C.amber,
                    cmd: C.accentText,
                    error: C.red,
                  };
                  return (
                    <div
                      key={log.id}
                      style={{
                        display: 'flex',
                        gap: 8,
                        padding: '5px 10px',
                        borderRadius: 8,
                        background: C.panel,
                        fontSize: 11,
                        lineHeight: '16px',
                        fontFamily: 'var(--font-mono)',
                      }}
                    >
                      <span style={{ color: C.textMuted, flexShrink: 0 }}>{log.timestamp}</span>
                      <span style={{ color: levelColor[log.level] ?? C.textSecondary, wordBreak: 'break-word' }}>
                        {log.message}
                      </span>
                    </div>
                  );
                })
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { memo, useCallback } from 'react';
import { X } from 'lucide-react';
import { toast } from 'sonner';
import { C } from '@/lib/theme';
import { AGENTS } from '@/lib/agents';
import { useTaskStore } from '@/stores/taskStore';
import { commands } from '@/bindings';
import { useElapsedTime, formatElapsed } from '@/hooks/useElapsedTime';

/* ── Component ─────────────────────────────────────────── */

export const DecomposingBanner = memo(function DecomposingBanner() {
  const phase = useTaskStore((s) => s.orchestrationPhase);
  const orchestrationPlan = useTaskStore((s) => s.orchestrationPlan);
  const activePlan = useTaskStore((s) => s.activePlan);
  const elapsed = useElapsedTime(phase === 'decomposing');

  const masterAgent = orchestrationPlan?.masterAgent ?? 'claude';
  const agent = AGENTS[masterAgent];

  const handleCancel = useCallback(async () => {
    const taskId = activePlan?.task_id;
    if (!taskId) {
      toast.error('No active task to cancel');
      return;
    }
    try {
      const result = await commands.cancelProcess(taskId);
      if (result.status === 'error') {
        toast.error('Cancel failed', { description: String(result.error) });
      } else {
        toast.success('Orchestration cancelled');
        useTaskStore.getState().setOrchestrationPhase('failed');
        useTaskStore.getState().addOrchestrationLog({
          agent: masterAgent,
          level: 'warn',
          message: 'Orchestration cancelled by user',
        });
      }
    } catch (e) {
      toast.error('Cancel failed', { description: String(e) });
    }
  }, [activePlan, masterAgent]);

  if (phase !== 'decomposing') return null;

  return (
    <div
      className="decomposing-banner flex-shrink-0"
      style={{
        position: 'relative',
        overflow: 'hidden',
        borderBottom: `1px solid ${C.border}`,
      }}
    >
      {/* Shimmer background layer */}
      <div
        className="decomposing-shimmer"
        style={{
          position: 'absolute',
          inset: 0,
          opacity: 0.6,
          pointerEvents: 'none',
        }}
      />

      {/* Gradient border glow along bottom edge */}
      <div
        style={{
          position: 'absolute',
          bottom: 0,
          left: 0,
          right: 0,
          height: 1,
          background: `linear-gradient(90deg, transparent, ${agent.color}60, ${agent.color}30, transparent)`,
          pointerEvents: 'none',
        }}
      />

      {/* Content */}
      <div
        className="flex items-center gap-4 px-5 py-3 relative"
        style={{
          background: `linear-gradient(135deg, ${C.panel} 0%, ${C.bg} 100%)`,
          zIndex: 1,
        }}
      >
        {/* Agent icon */}
        <div
          className="flex items-center justify-center flex-shrink-0"
          style={{
            width: 32,
            height: 32,
            borderRadius: 10,
            background: agent.gradient,
            boxShadow: `0 0 16px ${agent.color}30`,
            fontSize: 14,
            fontWeight: 700,
            color: '#fff',
          }}
        >
          {agent.letter}
        </div>

        {/* Text content */}
        <div className="flex flex-col gap-0.5 flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <span
              style={{
                fontSize: 13,
                fontWeight: 600,
                color: C.textPrimary,
                fontFamily: 'Inter, sans-serif',
              }}
            >
              Analyzing your task
            </span>
            {/* Animated dots */}
            <span className="decomposing-dots" style={{ color: C.textSecondary, fontSize: 13 }}>
              <span className="decomposing-dot" style={{ animationDelay: '0ms' }}>.</span>
              <span className="decomposing-dot" style={{ animationDelay: '200ms' }}>.</span>
              <span className="decomposing-dot" style={{ animationDelay: '400ms' }}>.</span>
            </span>
          </div>
          <span
            style={{
              fontSize: 11,
              color: C.textSecondary,
              fontFamily: 'Inter, sans-serif',
            }}
          >
            {agent.label} is breaking down the task into sub-tasks
          </span>
        </div>

        {/* Timer */}
        <div
          className="flex items-center gap-1.5 flex-shrink-0"
          style={{
            padding: '3px 10px',
            borderRadius: 999,
            background: C.surface,
            border: `1px solid ${C.border}`,
            fontSize: 11,
            fontWeight: 600,
            fontFamily: "'JetBrains Mono', 'SF Mono', monospace",
            color: C.textSecondary,
            minWidth: 48,
            justifyContent: 'center',
          }}
        >
          {formatElapsed(elapsed)}
        </div>

        {/* Cancel button */}
        <button
          onClick={handleCancel}
          className="flex items-center gap-1.5 flex-shrink-0 transition-all"
          style={{
            padding: '5px 12px',
            borderRadius: 8,
            background: 'transparent',
            border: `1px solid ${C.borderStrong}`,
            color: C.textSecondary,
            fontSize: 11,
            fontWeight: 600,
            fontFamily: 'Inter, sans-serif',
            cursor: 'pointer',
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.background = C.redBg;
            e.currentTarget.style.borderColor = '#ef444460';
            e.currentTarget.style.color = C.red;
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.background = 'transparent';
            e.currentTarget.style.borderColor = C.borderStrong;
            e.currentTarget.style.color = C.textSecondary;
          }}
        >
          <X size={12} />
          Cancel
        </button>
      </div>
    </div>
  );
});

import { useMemo } from 'react';
import { LayoutGrid, Target, GitBranch, Code, ClipboardCheck, CheckCircle, Settings } from 'lucide-react';
import { useUIStore, type AppView } from '@/stores/uiStore';
import { useTaskStore } from '@/stores/taskStore';
import { QuickTaskPopover } from './QuickTaskPopover';
import { NotificationCenter } from '@/components/shared/NotificationCenter';

/**
 * Content header bar with session info, view tabs, quick task button,
 * and review notification.
 */
export function ContentHeader() {
  const activeView = useUIStore((s) => s.activeView);
  const setActiveView = useUIStore((s) => s.setActiveView);
  const storedSessionName = useUIStore((s) => s.sessionName);
  const tasks = useTaskStore((s) => s.tasks);
  const orchestrationPhase = useTaskStore((s) => s.orchestrationPhase);
  const activePlan = useTaskStore((s) => s.activePlan);

  const sessionName = storedSessionName || (activePlan ? 'Active Session' : 'No Session');
  const sessionStatus = orchestrationPhase === 'idle' ? 'idle' : 'running';
  const hasReviewReady = orchestrationPhase === 'reviewing' || orchestrationPhase === 'completed';
  const hasActivity = tasks.size > 0 || orchestrationPhase !== 'idle';
  const hasCompletedTasks = Array.from(tasks.values()).some((t) => t.status === 'completed');

  const tabs: { key: AppView; label: string; icon: React.ReactNode }[] = useMemo(() => {
    const base: { key: AppView; label: string; icon: React.ReactNode }[] = [
      { key: 'kanban', label: 'Working', icon: <LayoutGrid size={14} /> },
    ];
    if (hasActivity) {
      base.push(
        { key: 'usage', label: 'Usage', icon: <Target size={14} /> },
        { key: 'git', label: 'Git', icon: <GitBranch size={14} /> },
        { key: 'code', label: 'Code', icon: <Code size={14} /> },
      );
    }
    // Dynamic Review tab when orchestration is reviewing or completed
    if (orchestrationPhase === 'reviewing' || orchestrationPhase === 'completed') {
      base.push({ key: 'review', label: 'Review', icon: <ClipboardCheck size={14} /> });
    }
    // Dynamic Done tab when orchestration completed or tasks finished
    if (orchestrationPhase === 'completed' || hasCompletedTasks) {
      base.push({ key: 'done', label: 'Done', icon: <CheckCircle size={14} /> });
    }
    // Settings always last
    base.push({ key: 'settings', label: 'Settings', icon: <Settings size={14} /> });
    return base;
  }, [hasActivity, orchestrationPhase, hasCompletedTasks]);

  return (
    <div className="flex items-center gap-0 border-b border-wc-border bg-wc-panel h-[44px] shrink-0 pl-1 pr-4">
      {/* Session name + status */}
      <div className="flex items-center gap-2.5 px-4 border-r border-wc-border mr-2 min-w-[180px]">
        <span className="relative inline-flex">
          <span
            className="size-2 rounded-full block"
            style={{ background: sessionStatus === 'running' ? 'var(--color-wc-amber)' : 'var(--color-wc-text-muted)' }}
          />
          {sessionStatus === 'running' && (
            <span className="absolute inset-0 rounded-full animate-ping bg-wc-amber opacity-40" />
          )}
        </span>
        <span className="text-sm font-semibold text-wc-text-primary">
          {sessionName}
        </span>
      </div>

      {/* Tabs */}
      <div className="flex items-center h-full" role="tablist">
        {tabs.map((tab) => (
          <button
            key={tab.key}
            role="tab"
            aria-selected={activeView === tab.key}
            onClick={() => setActiveView(tab.key)}
            className={`flex items-center gap-1.5 h-full px-4 text-xs font-medium border-b-2 transition-colors ${
              activeView === tab.key
                ? 'border-wc-accent text-wc-accent-text'
                : 'border-transparent text-wc-text-muted'
            }`}
          >
            <span>{tab.icon}</span>
            <span>{tab.label}</span>
          </button>
        ))}
      </div>

      {/* Quick task button */}
      <QuickTaskPopover />

      <div className="flex-1" />

      {/* Notification center */}
      <NotificationCenter />

      {/* Review notification */}
      {hasReviewReady && activeView !== 'review' && activeView !== 'done' && (
        <button
          onClick={() => setActiveView('review')}
          className="mr-3 flex items-center gap-1.5 px-2.5 py-1 rounded-lg text-xs font-medium transition-all bg-wc-accent-soft text-wc-accent-text border border-wc-accent/25"
        >
          <span className="size-1.5 rounded-full bg-wc-accent" />
          Review
        </button>
      )}
    </div>
  );
}

import { useState, useRef } from 'react';
import { History, Settings } from 'lucide-react';
import { C } from '@/lib/theme';
import { useUIStore } from '@/stores/uiStore';
import { useTaskStore } from '@/stores/taskStore';
import { SessionHistory } from '@/components/shared/SessionHistory';

/* ── Tooltip ─────────────────────────────────────────────── */

function Tooltip({ label, children }: { label: string; children: React.ReactNode }) {
  const [show, setShow] = useState(false);
  const timerRef = useRef<ReturnType<typeof setTimeout>>(null);
  return (
    <div
      className="relative"
      onMouseEnter={() => { timerRef.current = setTimeout(() => setShow(true), 150); }}
      onMouseLeave={() => { if (timerRef.current) clearTimeout(timerRef.current); setShow(false); }}
    >
      {children}
      {show && (
        <div
          className="absolute left-full ml-2.5 top-1/2 -translate-y-1/2 z-50 px-2.5 py-1.5 rounded-lg text-xs font-medium whitespace-nowrap pointer-events-none"
          style={{
            background: '#1e1e30',
            color: C.textPrimary,
            border: `1px solid ${C.borderStrong}`,
            boxShadow: '0 4px 16px rgba(0,0,0,0.5)',
          }}
        >
          {label}
          <div
            className="absolute right-full top-1/2 -translate-y-1/2 border-4 border-transparent"
            style={{ borderRightColor: '#1e1e30' }}
          />
        </div>
      )}
    </div>
  );
}

/* ── Icon Button ─────────────────────────────────────────── */

function IconButton({
  active,
  onClick,
  children,
  'aria-label': ariaLabel,
}: {
  active?: boolean;
  onClick: () => void;
  children: React.ReactNode;
  'aria-label'?: string;
}) {
  return (
    <button
      onClick={onClick}
      aria-label={ariaLabel}
      className={`w-9 h-9 rounded-[10px] flex items-center justify-center border-none cursor-pointer transition-all duration-150 ease-out ${
        active
          ? 'bg-wc-accent-soft text-wc-accent-text'
          : 'bg-transparent text-wc-text-muted hover:bg-wc-surface-hover hover:text-wc-text-secondary'
      }`}
    >
      {children}
    </button>
  );
}

/* ── Session Button ──────────────────────────────────────── */

function SessionButton({
  label,
  statusColor,
  active,
  onClick,
}: {
  label: string;
  statusColor: string;
  active: boolean;
  onClick: () => void;
}) {
  return (
    <Tooltip label={label}>
      <button
        onClick={onClick}
        className={`w-9 h-9 rounded-[10px] flex items-center justify-center relative text-[13px] font-semibold cursor-pointer transition-all duration-150 ease-out ${
          active
            ? 'bg-wc-accent-soft text-wc-accent-text border border-wc-accent'
            : 'bg-wc-surface text-wc-text-secondary border border-wc-border hover:border-wc-border-strong hover:bg-wc-surface-hover'
        }`}
      >
        {label.charAt(0).toUpperCase()}
        <span
          style={{
            position: 'absolute',
            bottom: -2,
            right: -2,
            width: 8,
            height: 8,
            borderRadius: '50%',
            background: statusColor,
            border: `2px solid ${C.sidebar}`,
          }}
        />
      </button>
    </Tooltip>
  );
}

/* ── Sidebar ─────────────────────────────────────────────── */

