      </Tooltip>

      {/* Divider */}
      <div
        style={{
          width: 24,
          height: 1,
          background: C.border,
          marginTop: 12,
          marginBottom: 12,
          flexShrink: 0,
        }}
      />

      {/* Sessions */}
      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          gap: 8,
          flexShrink: 0,
        }}
      >
        {hasSession && (
          <SessionButton
            label={displayLabel}
            statusColor={phaseToColor(orchestrationPhase)}
