import { type ReactNode, useMemo, useState } from 'react';
import { C } from '@/lib/theme';
import { Sidebar } from './Sidebar';
import { ContentHeader } from './ContentHeader';
import { QuestionBanner } from './QuestionBanner';
import { useUIStore } from '@/stores/uiStore';
import { useTaskStore } from '@/stores/taskStore';
import { SetupPanel } from './SetupPanel';
import { RateLimitDialog } from '@/components/orchestration/RateLimitDialog';
import { useHotkeys } from '@/hooks/useHotkeys';
import { useOrchestrationLaunch } from '@/hooks/useOrchestrationLaunch';
import { StagePipeline } from '@/components/orchestration/StagePipeline';
import { CommandPalette } from '@/components/shared/CommandPalette';
import { OnboardingWizard } from '@/components/shared/OnboardingWizard';
import type { AppView } from '@/stores/uiStore';

interface AppShellProps {
  children: ReactNode;
}

export function AppShell({ children }: AppShellProps) {
  const activeView = useUIStore((s) => s.activeView);
  const setActiveView = useUIStore((s) => s.setActiveView);
  const showSetup = useUIStore((s) => s.showSetup);
  const orchestrationPhase = useTaskStore((s) => s.orchestrationPhase);
  const doneTasks = useTaskStore((s) => {
    let count = 0;
    for (const t of s.tasks.values()) if (t.status === 'completed') count++;
    return count;
  });
  const totalTasks = useTaskStore((s) => s.tasks.size);
  const pendingQuestion = useTaskStore((s) => s.pendingQuestion);
  const activePlan = useTaskStore((s) => s.activePlan);
  const showQuickTask = useUIStore((s) => s.showQuickTask);
  const setShowQuickTask = useUIStore((s) => s.setShowQuickTask);
  const selectedTaskId = useUIStore((s) => s.selectedTaskId);
  const setSelectedTaskId = useUIStore((s) => s.setSelectedTaskId);
  const { handleLaunch } = useOrchestrationLaunch();
  const [commandPaletteOpen, setCommandPaletteOpen] = useState(false);

  // Global keyboard shortcuts
  const viewShortcuts: [string, AppView][] = [
    ['1', 'kanban'],
    ['2', 'usage'],
    ['3', 'git'],
    ['4', 'code'],
  ];

  const hotkeys = useMemo(
    () => [
      // Cmd+P — toggle command palette
      {
        key: 'p',
        meta: true,
        handler: (e: KeyboardEvent) => {
          e.preventDefault();
          setCommandPaletteOpen((v) => !v);
        },
      },
      // Cmd+K — toggle quick task modal
      {
        key: 'k',
        meta: true,
        handler: (e: KeyboardEvent) => {
          e.preventDefault();
          setShowQuickTask(!showQuickTask);
        },
      },
      // Cmd+1..5 — switch views
      ...viewShortcuts.map(([digit, view]) => ({
        key: digit,
        meta: true,
        handler: (e: KeyboardEvent) => {
          e.preventDefault();
          setActiveView(view);
        },
      })),
      // Escape — close task detail panel and quick task modal
      {
        key: 'Escape',
        handler: (_e: KeyboardEvent) => {
          if (showQuickTask) {
            setShowQuickTask(false);
          } else if (selectedTaskId) {
            setSelectedTaskId(null);
          }
        },
      },
    ],
    [showQuickTask, selectedTaskId, setShowQuickTask, setActiveView, setSelectedTaskId, commandPaletteOpen],
  );

  useHotkeys(hotkeys);

  // Derived state already computed via selectors above

  return (
    <div
      className="h-screen flex flex-col overflow-hidden"
      style={{ background: C.bg, color: C.textPrimary }}
    >
      <div className="flex flex-1 overflow-hidden relative">
        <Sidebar />

        {/* Content area */}
        <div className="flex flex-col flex-1 overflow-hidden" data-testid="main-content">
          <ContentHeader />

          {/* Pending question banner */}
          {pendingQuestion && activeView !== 'review' && (
            <QuestionBanner pendingQuestion={pendingQuestion} />
          )}

          {/* Stage pipeline (shown when orchestration is active) */}
          {orchestrationPhase !== 'idle' && <StagePipeline />}


          {/* Progress strip (only on kanban) */}
          {activeView === 'kanban' && (
            <div
              className="flex items-center gap-3 px-5 py-2 border-b flex-shrink-0 text-xs"
              style={{ borderColor: C.border, background: C.bg }}
            >
              <span style={{ color: C.textMuted }}>
                {doneTasks}/{totalTasks} tasks
              </span>
              <div
                className="flex-1 h-1 rounded-full overflow-hidden"
                style={{ background: C.borderStrong, maxWidth: 160 }}
              >
                <div
                  className="h-full rounded-full"
                  style={{
                    width: totalTasks > 0 ? `${(doneTasks / totalTasks) * 100}%` : '0%',
                    background: `linear-gradient(90deg, ${C.accent}, ${C.green})`,
                  }}
                />
              </div>
              <div className="flex-1" />
              {activePlan && (
                <div className="flex items-center gap-1.5 text-xs" style={{ color: C.amber }}>
                  <span className="w-1.5 h-1.5 rounded-full" style={{ background: C.amber }} />
                  Active
                </div>
              )}
            </div>
          )}

          {/* Main content */}
          {children}
        </div>

        {/* Setup overlay */}
        {showSetup && <SetupPanel onLaunch={handleLaunch} />}
        <RateLimitDialog />
      </div>


      {/* Command Palette (Cmd+P) */}
      <CommandPalette open={commandPaletteOpen} onClose={() => setCommandPaletteOpen(false)} />

      {/* First-run onboarding */}
      <OnboardingWizard />
    </div>
  );
}

import { useMemo, useEffect, useState } from 'react';
import { useUIStore } from '@/stores/uiStore';
import { useTaskStore } from '@/stores/taskStore';

/**
 * Bottom status bar showing activity status, session info, and progress.
 */
export function StatusBar() {
  const developerMode = useUIStore((s) => s.developerMode);
  const storedSessionName = useUIStore((s) => s.sessionName);
  const orchestrationPhase = useTaskStore((s) => s.orchestrationPhase);
  const doneTasks = useTaskStore((s) => {
    let count = 0;
    for (const t of s.tasks.values()) if (t.status === 'completed') count++;
    return count;
  });
  const totalTasks = useTaskStore((s) => s.tasks.size);
  const activePlan = useTaskStore((s) => s.activePlan);

  const isOrchestrating = orchestrationPhase !== 'idle';

  // Activity heartbeat tracking
  const [secondsAgo, setSecondsAgo] = useState<number | null>(null);

  useEffect(() => {
    if (!isOrchestrating) {
      setSecondsAgo(null);
      return;
    }
    const interval = setInterval(() => {
      const logs = useTaskStore.getState().orchestrationLogs;
      if (logs.length === 0) {
        setSecondsAgo(null);
        return;
      }
      const lastLog = logs[logs.length - 1];
      const parts = lastLog.timestamp.split(':');
      if (parts.length === 3) {
        const now = new Date();
        const logDate = new Date();
        logDate.setHours(parseInt(parts[0], 10), parseInt(parts[1], 10), parseInt(parts[2], 10));
        const diff = Math.floor((now.getTime() - logDate.getTime()) / 1000);
        setSecondsAgo(Math.max(0, diff));
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [isOrchestrating]);

  const activityStatus: 'active' | 'waiting' | 'idle' = useMemo(() => {
    if (!isOrchestrating) return 'idle';
    if (secondsAgo === null) return 'idle';
    if (secondsAgo <= 15) return 'active';
    return 'waiting';
  }, [isOrchestrating, secondsAgo]);

  const sessionName = storedSessionName || (activePlan ? 'Active Session' : 'No Session');

  return (
    <div role="status" aria-live="polite" className="flex items-center gap-4 px-4 border-t border-wc-border bg-[#07070f] text-[11px] h-[26px] shrink-0">
      <div className="flex items-center gap-1.5 text-wc-text-muted">
        {activityStatus === 'active' ? (
          <>
            <span className="heartbeat-pulse size-1.5 rounded-full bg-wc-green inline-block shrink-0" />
            <span className="text-wc-green">Processing...</span>
          </>
        ) : activityStatus === 'waiting' ? (
          <>
            <span className="size-1.5 rounded-full bg-wc-amber inline-block shrink-0" />
            <span className="text-wc-amber">Waiting for response...</span>
          </>
        ) : (
          <>
            <span className="size-1.5 rounded-full bg-wc-green" />
            Agents ready
          </>
        )}
      </div>
      {activityStatus !== 'idle' && secondsAgo !== null && (
        <>
          <span className="text-wc-border-strong">|</span>
          <div className="text-wc-text-muted">
            Last activity:{' '}
            <span className={activityStatus === 'active' ? 'text-wc-green' : 'text-wc-amber'}>
              {secondsAgo}s ago
            </span>
          </div>
        </>
      )}
      <span className="text-wc-border-strong">|</span>
      <div className="text-wc-text-muted">
        Session: <span className="text-wc-text-secondary">{sessionName}</span>
      </div>
      <span className="text-wc-border-strong">|</span>
      <div className="text-wc-text-muted">
        Progress:{' '}
        <span className="text-wc-amber">
          {totalTasks > 0 ? Math.round((doneTasks / totalTasks) * 100) : 0}%
        </span>
      </div>
      <div className="flex-1" />
      {developerMode && (
        <div className="flex items-center gap-1 text-wc-accent-text">
          <span className="size-1.5 rounded-full bg-wc-accent-text" />
          Developer Mode
        </div>
      )}
      <span className="text-wc-border-strong">|</span>
      <span className="text-wc-text-muted">WhaleCode v0.1.0</span>
    </div>
  );
}

import { useState, useRef, useCallback, useEffect, useMemo } from 'react';
import { ChevronDown, ChevronUp, Terminal } from 'lucide-react';
import { C, LOG_COLOR } from '@/lib/theme';
import { AGENTS } from '@/lib/agents';
import { useTaskStore } from '@/stores/taskStore';

/**
 * VS Code-style collapsible bottom panel showing orchestration logs.
 * Replaces the separate TerminalView — always available at the bottom of any view.
 */
interface TerminalBottomPanelProps {
  open: boolean;
  onToggle: () => void;
  devMode?: boolean;
}

export function TerminalBottomPanel({ open, onToggle }: TerminalBottomPanelProps) {
  const orchestrationLogs = useTaskStore((s) => s.orchestrationLogs);
  const orchestrationPhase = useTaskStore((s) => s.orchestrationPhase);
  const [height, setHeight] = useState(220);
  const logRef = useRef<HTMLDivElement>(null);
  const resizeRef = useRef<{ startY: number; startHeight: number } | null>(null);
  const isActive = orchestrationPhase !== 'idle';

  // Auto-scroll on new logs
  useEffect(() => {
    if (open && logRef.current) {
      logRef.current.scrollTop = logRef.current.scrollHeight;
    }
  }, [orchestrationLogs.length, open]);

  // Resize drag
  const handleResizeStart = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    resizeRef.current = { startY: e.clientY, startHeight: height };
    const onMove = (me: MouseEvent) => {
      if (!resizeRef.current) return;
      const delta = resizeRef.current.startY - me.clientY;
      setHeight(Math.max(100, Math.min(600, resizeRef.current.startHeight + delta)));
    };
    const onUp = () => {
      resizeRef.current = null;
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
    };
    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
  }, [height]);

  const logCount = orchestrationLogs.length;
  const errorCount = useMemo(() => orchestrationLogs.filter(l => l.level === 'error').length, [orchestrationLogs]);
  const visibleLogs = orchestrationLogs.slice(-200);

  return (
    <div style={{ flexShrink: 0, borderTop: `1px solid ${C.border}` }}>
      {/* Toggle bar — always visible */}
      <button
        type="button"
        onClick={onToggle}
        style={{
          width: '100%',
          display: 'flex',
          alignItems: 'center',
          gap: 8,
          padding: '4px 12px',
          background: C.panel,
          border: 'none',
          color: C.textMuted,
          fontSize: 11,
          fontFamily: 'Inter, sans-serif',
          cursor: 'pointer',
          textAlign: 'left',
        }}
      >
        <Terminal size={12} />
        <span style={{ fontWeight: 600 }}>Output</span>
        {logCount > 0 && (
          <span style={{
            padding: '0 6px',
            borderRadius: 999,
            background: C.surface,
            fontSize: 10,
            color: C.textSecondary,
          }}>
            {logCount}
          </span>
        )}
        {errorCount > 0 && (
          <span style={{
            padding: '0 6px',
            borderRadius: 999,
            background: C.redBg,
            fontSize: 10,
            color: C.red,
            fontWeight: 600,
          }}>
            {errorCount} error{errorCount !== 1 ? 's' : ''}
          </span>
        )}
        {isActive && (
          <span
            className="heartbeat-pulse"
            style={{
              width: 6, height: 6, borderRadius: '50%',
              background: C.green, display: 'inline-block',
            }}
          />
        )}
        <span style={{ flex: 1 }} />
        {open ? <ChevronDown size={12} /> : <ChevronUp size={12} />}
      </button>

      {/* Panel content */}
      <div style={{ height: open ? height : 0, overflow: 'hidden', transition: 'height 200ms cubic-bezier(0.4, 0, 0.2, 1)', display: 'flex', flexDirection: 'column', background: '#07070f', willChange: open ? 'height' : 'auto' }}>
          {/* Resize handle */}
          <div
            onMouseDown={handleResizeStart}
            style={{
              height: 3,
              cursor: 'row-resize',
              background: 'transparent',
              flexShrink: 0,
            }}
            onMouseEnter={(e) => { e.currentTarget.style.background = C.accent; }}
            onMouseLeave={(e) => { e.currentTarget.style.background = 'transparent'; }}
          />

          {/* Log content */}
          <div
            ref={logRef}
            style={{
              flex: 1,
              overflowY: 'auto',
              padding: '8px 12px',
              fontFamily: 'var(--font-mono)',
              fontSize: 11,
              lineHeight: '18px',
            }}
          >
            {visibleLogs.length === 0 ? (
              <div style={{ color: C.textMuted, padding: '20px 0', textAlign: 'center' }}>
                No output yet. Start an orchestration to see logs here.
              </div>
            ) : (
              visibleLogs.map((log) => (
                <div key={log.id} style={{ display: 'flex', gap: 8, padding: '2px 0' }}>
                  <span style={{ color: C.textMuted, flexShrink: 0, width: 60 }}>{log.timestamp}</span>
                  <span style={{
                    width: 16, height: 16, borderRadius: 4, flexShrink: 0,
                    background: AGENTS[log.agent]?.gradient ?? C.surface,
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: 8, fontWeight: 700, color: '#fff',
                  }}>
                    {AGENTS[log.agent]?.letter ?? '?'}
                  </span>
                  <span style={{
                    color: LOG_COLOR[log.level] ?? C.textSecondary,
                    wordBreak: 'break-word',
                    whiteSpace: 'pre-wrap',
                    maxHeight: 200,
                    overflow: 'auto',
                    display: 'block',
                    flex: 1,
                  }}>
                    {log.message}
                  </span>
                </div>
              ))
            )}
          </div>
        </div>
    </div>
  );
}

